const $=id=>document.getElementById(id); let USER=JSON.parse(localStorage.getItem('user')||'null'); let current='dashboard'; let cart=[];
const modules=['dashboard','receitas','produtos','compras','producao','pedidos','clientes','pdv','campanhas','financeiro','pro_labore','relatorios','usuarios','configuracoes','backup'];
const labels={dashboard:'📊 DASHBOARD',receitas:'📖 RECEITAS',produtos:'📦 PRODUTOS / ESTOQUE',compras:'🧾 COMPRAS',producao:'⚖️ PRODUÇÃO',pedidos:'🗓️ PEDIDOS / AGENDAMENTOS',clientes:'👥 CLIENTES',pdv:'🛒 PDV / VENDAS',campanhas:'🟩 CAMPANHAS WHATSAPP',financeiro:'💰 FINANCEIRO',pro_labore:'💵 PRÓ-LABORE',relatorios:'📈 RELATÓRIOS',usuarios:'🔐 USUÁRIOS / PERMISSÕES',configuracoes:'⚙️ CONFIGURAÇÕES',backup:'💾 BACKUP'};
const money=n=>Number(n||0).toLocaleString('pt-BR',{style:'currency',currency:'BRL'}); const upper=v=>String(v??'').toUpperCase();
async function api(url,opt={}){opt.headers={...(opt.headers||{}),'Content-Type':opt.body instanceof FormData?undefined:'application/json'}; if(!opt.headers['Content-Type']) delete opt.headers['Content-Type']; const r=await fetch(url,opt); const j=await r.json().catch(()=>({ok:false,error:'ERRO DE RESPOSTA'})); if(!j.ok) throw new Error(j.error||'ERRO'); return j.data;}
function can(m){return !USER||USER.perfil==='admin'||USER.permissoes?.todas||USER.permissoes?.[m]}
function layout(){ if(!USER){document.body.innerHTML=`<div class="modal"><div class="modalbox" style="max-width:430px"><h2>CONFEITARIA OLITECH</h2><p class="muted">ERP PROFISSIONAL</p><label>USUÁRIO<input id="loginU" value="admin"></label><label>SENHA<input id="loginS" type="password" value="admin"></label><button onclick="login()">ENTRAR</button></div></div>`;return} document.body.innerHTML=`<div class="app"><aside class="side"><div class="brand">🧁 CONFEITARIA <span>OLITECH</span></div><nav class="nav">${modules.filter(can).map(m=>`<a href="#" id="nav_${m}" onclick="openMod('${m}')">${labels[m]}</a>`).join('')}</nav><div class="userbox"><b>${USER.nome}</b><br><span style="color:#e23cff">${USER.perfil}</span><br><br><button class="secondary" onclick="logout()">SAIR</button></div></aside><main class="main"><div class="top"><div><h1 id="title"></h1><p>VISÃO GERAL DA SUA CONFEITARIA</p></div><div class="actions"><button class="green" onclick="abrirWhatsQr()">QR WHATSAPP</button><button onclick="abrirSobre()">SOBRE</button></div></div><div id="content"></div></main></div><div id="modal" class="modal hidden"><div class="modalbox"><button class="modal-close" onclick="fecharModal()">X</button><div id="modalContent"></div></div></div>`; openMod(current)}
async function login(){try{USER=await api('/api/login',{method:'POST',body:JSON.stringify({usuario:$('loginU').value,senha:$('loginS').value})}); localStorage.setItem('user',JSON.stringify(USER)); layout()}catch(e){alert(e.message)}} function logout(){localStorage.removeItem('user');USER=null;layout()}
function openMod(m){if(!can(m))return alert('SEM PERMISSÃO');current=m; document.querySelectorAll('.nav a').forEach(a=>a.classList.remove('active')); setTimeout(()=>{if($('nav_'+m))$('nav_'+m).classList.add('active')}); $('title').textContent=labels[m].replace(/[📊📖📦🧾⚖️🗓️👥🛒🟩💰💵📈🔐⚙️💾]/g,''); window[m==='pro_labore'?'proLabore':m]?.();}
function inputFor(f,v=''){let type=f.includes('data')||f==='vencimento'||f==='pagamento'||f==='validade'?'date':(f.includes('email')?'email':(f.includes('valor')||f.includes('preco')||f.includes('custo')||f.includes('estoque')||f.includes('quantidade')||f.includes('margem')||f==='total'?'number':'text')); if(f==='observacoes'||f==='modo_preparo'||f==='mensagem') return `<label class="full">${f}<textarea class="upper" id="f_${f}">${v||''}</textarea></label>`; return `<label>${f}<input class="upper" id="f_${f}" type="${type}" value="${v??''}" oninput="calcProdutoForm()"></label>`}
function table(rows,cols,t){return `<div style="overflow:auto"><table><thead><tr>${cols.map(c=>`<th>${c}</th>`).join('')}<th>AÇÕES</th></tr></thead><tbody>${(rows||[]).map(r=>`<tr>${cols.map(c=>`<td>${fmt(c,r[c])}</td>`).join('')}<td><button class="secondary" onclick='formCrud("${t}","EDITAR",${JSON.stringify(cols)},${JSON.stringify(r).replace(/'/g,'&#39;')})'>EDITAR</button> <button class="red" onclick="del('${t}','${r.id}')">EXCLUIR</button></td></tr>`).join('')}</tbody></table></div>`}
function simple(rows,cols){return `<table><thead><tr>${cols.map(c=>`<th>${c}</th>`).join('')}</tr></thead><tbody>${(rows||[]).map(r=>`<tr>${cols.map(c=>`<td>${fmt(c,r[c])}</td>`).join('')}</tr>`).join('')}</tbody></table>`}
function fmt(c,v){if(v==null)return ''; if(String(c).includes('valor')||String(c).includes('preco')||c==='total'||String(c).includes('custo'))return money(v); if(typeof v==='object')return JSON.stringify(v); return upper(v)}
async function crud(t,titulo,cols){$('content').innerHTML=`<div class="panel"><div class="actions"><input id="busca" placeholder="PESQUISAR ACIMA DE 2 LETRAS" oninput="if(this.value.length>1||!this.value) crud('${t}','${titulo}',${JSON.stringify(cols)})" value="${$('busca')?.value||''}"><button onclick='formCrud("${t}","${titulo}",${JSON.stringify(cols)})'>+ NOVO</button></div><div id="lista"></div></div>`; const d=await api('/api/'+t+'?busca='+encodeURIComponent($('busca')?.value||'')); $('lista').innerHTML=table(d,cols,t)}
function formCrud(t,titulo,cols,item={}){window.edit={t,cols,id:item.id}; abrirModal(`<h2>${titulo}</h2><div class="formgrid">${cols.map(c=>inputFor(c,item[c])).join('')}</div><button onclick="saveCrud()">SALVAR</button>`); if(t==='produtos') calcProdutoForm()}
async function saveCrud(){const {t,cols,id}=window.edit; const body={}; cols.forEach(c=>{const el=$('f_'+c); if(el){body[c]=el.value}}); if(id)body.id=id; await api('/api/'+t,{method:'POST',body:JSON.stringify(body)}); fecharModal(); window[current==='pro_labore'?'proLabore':current]?.()}
async function del(t,id){if(confirm('EXCLUIR REGISTRO?')){await api('/api/'+t+'/'+id,{method:'DELETE'}); window[current==='pro_labore'?'proLabore':current]?.()}}
async function dashboard(){const r=await api('/api/dashboard/resumo'); $('content').innerHTML=`<div class="grid g4"><div class="panel"><h3>FATURAMENTO HOJE</h3><div class="kpi">${money(r.faturamentoHoje)}</div></div><div class="panel"><h3>PEDIDOS HOJE</h3><div class="kpi">${r.pedidosHoje.length}</div></div><div class="panel"><h3>RECEITAS</h3><div class="kpi">${r.receitas}</div></div><div class="panel"><h3>PRODUTOS</h3><div class="kpi">${r.produtos}</div></div></div><div class="grid g2"><div class="panel"><h3>AGENDAMENTOS DE HOJE</h3>${simple(r.pedidosHoje,['cliente_nome','data_entrega','hora_entrega','status','total'])}</div><div class="panel"><h3>ALERTA DE ESTOQUE</h3>${simple(r.alertasEstoque,['nome','estoque_atual','estoque_minimo','unidade'])}</div></div>`}
function produtos(){crud('produtos','PRODUTOS / ESTOQUE',['nome','tipo','categoria','unidade','codigo_barras','custo_unitario','preco_venda','margem_percentual','estoque_atual','estoque_minimo','validade','fornecedor_principal','ultima_compra_valor','custo_medio','quantidade_compras'])}
async function calcProdutoForm(){if(!$('f_custo_unitario'))return; const c=Number($('f_custo_unitario')?.value||0), v=Number($('f_preco_venda')?.value||0), m=Number($('f_margem_percentual')?.value||0); if(document.activeElement?.id==='f_margem_percentual'&&c&&m&&!v) $('f_preco_venda').value=(c*(1+m/100)).toFixed(2); if(document.activeElement?.id==='f_preco_venda'&&c&&v) $('f_margem_percentual').value=(((v-c)/c)*100).toFixed(2)}
function clientes(){crud('clientes','CLIENTES',['nome','telefone','whatsapp','email','cpf_cnpj','rua','numero','complemento','bairro','cidade','estado','cep','observacoes'])}
function receitas(){crud('receitas','RECEITAS',['nome','categoria','peso_base','unidade_base','rendimento','custo_total','preco_venda','margem_percentual','modo_preparo'])}
async function producao(){const rec=await api('/api/receitas'); $('content').innerHTML=`<div class="grid g2"><div class="panel"><h3>CALCULAR / IMPRIMIR PRODUÇÃO</h3><label>RECEITA<select id="prodRec">${rec.map(r=>`<option value="${r.id}">${r.nome}</option>`).join('')}</select></label><label>PESO BASE<input id="pesoBase" type="number" value="1"></label><label>PESO DESEJADO<input id="pesoDesejado" type="number" value="1.5"></label><label>MARGEM %<input id="margemProd" type="number" value="100"></label><button onclick="calcularProducao()">CALCULAR / GERAR IMPRESSÃO</button><button class="green" onclick="baixarEstoqueProducao()">BAIXAR ESTOQUE</button></div><div class="panel"><h3>RESULTADO</h3><div id="resProd"></div></div></div><div class="panel"><h3>HISTÓRICO</h3><div id="histProd"></div></div>`; const h=await api('/api/producoes'); $('histProd').innerHTML=table(h,['descricao','responsavel','peso_desejado','custo_total','status','created_at'],'producoes')}
async function calcularProducao(){const r=await api('/api/receitas/calcular',{method:'POST',body:JSON.stringify({receita_id:$('prodRec').value,peso_base:$('pesoBase').value,peso_desejado:$('pesoDesejado').value,margem_percentual:$('margemProd').value})}); window.lastCalc=r; $('resProd').innerHTML=`<div class="kpi">CUSTO: ${money(r.custo)}<br>VENDA: ${money(r.venda)}</div>${simple(r.detalhes,['produto','quantidade','unidade','custo_unitario','custo_total'])}<button onclick="imprimirProducao()">IMPRIMIR / PDF</button>`}
function imprimirProducao(){const r=window.lastCalc;if(!r)return alert('CALCULE PRIMEIRO'); const html=`<div class="print-area"><h1>FICHA DE PRODUÇÃO - CONFEITARIA OLITECH</h1><h2>${r.receita.nome}</h2><p>PESO DESEJADO: ${r.peso_desejado} | CUSTO: ${money(r.custo)} | VENDA SUGERIDA: ${money(r.venda)}</p>${simple(r.detalhes,['produto','quantidade','unidade','custo_unitario','custo_total'])}<h3>MODO DE PREPARO</h3><p>${r.receita.modo_preparo||''}</p><br><p>RESPONSÁVEL: __________________________</p></div>`; const w=open('','_blank'); w.document.write(html); w.document.close(); w.print()}
async function baixarEstoqueProducao(){const r=await api('/api/producao/baixar-estoque',{method:'POST',body:JSON.stringify({receita_id:$('prodRec').value,peso_base:$('pesoBase').value,peso_desejado:$('pesoDesejado').value,descricao:'PRODUÇÃO',responsavel:USER.nome})}); alert('ESTOQUE BAIXADO'); producao()}
async function compras(){const prods=await api('/api/produtos'); const forn=await api('/api/fornecedores'); $('content').innerHTML=`<div class="grid g2"><div class="panel"><h3>LANÇAR COMPRA / NF</h3><label>FORNECEDOR<select id="cFornecedor">${forn.map(f=>`<option value="${f.id}">${f.nome}</option>`).join('')}</select></label><input id="nf" placeholder="NÚMERO NF"><input id="dataCompra" type="date"><input id="vencCompra" type="date"><select id="pCompra">${prods.map(p=>`<option value="${p.id}">${p.nome}</option>`).join('')}</select><input id="qCompra" type="number" placeholder="QUANTIDADE"><input id="vuCompra" type="number" placeholder="VALOR UNITÁRIO"><button onclick="addCompraItem()">ADICIONAR ITEM</button><button class="green" onclick="salvarCompra()">SALVAR COMPRA E ENTRAR ESTOQUE</button></div><div class="panel"><h3>ITENS</h3><div id="itensCompra"></div></div></div><div class="panel"><h3>COMPRAS</h3><div id="listaCompras"></div></div>`; window.compraItens=[]; listarCompras()}
function addCompraItem(){const s=$('pCompra').selectedOptions[0]; window.compraItens.push({produto_id:$('pCompra').value,produto:s.textContent,quantidade:Number($('qCompra').value||0),valor_unitario:Number($('vuCompra').value||0)}); renderCompraItens()} function renderCompraItens(){$('itensCompra').innerHTML=simple(window.compraItens.map(i=>({...i,total:i.quantidade*i.valor_unitario})),['produto','quantidade','valor_unitario','total'])}
async function salvarCompra(){await api('/api/compras/lancar',{method:'POST',body:JSON.stringify({fornecedor_id:$('cFornecedor').value,numero_nf:$('nf').value,data_compra:$('dataCompra').value,vencimento:$('vencCompra').value,status:'LANÇADA',itens:window.compraItens})}); alert('COMPRA LANÇADA'); compras()} async function listarCompras(){const d=await api('/api/compras'); $('listaCompras').innerHTML=table(d,['numero_nf','data_compra','vencimento','total','status'],'compras')}
function fornecedores(){crud('fornecedores','FORNECEDORES',['nome','telefone','whatsapp','email','cnpj','cidade','estado','observacoes'])}
function pedidos(){crud('pedidos','PEDIDOS / AGENDAMENTOS',['cliente_nome','telefone','data_entrega','hora_entrega','endereco_entrega','status','subtotal','desconto','total','forma_pagamento','observacoes'])}
async function pdv(){const prods=await api('/api/produtos'); cart=[]; $('content').innerHTML=`<div class="grid g2"><div class="panel"><h3>PDV</h3><input id="vCliente" class="upper" value="CONSUMIDOR"><select id="vProd">${prods.map(p=>`<option value="${p.id}" data-nome="${p.nome}" data-preco="${p.preco_venda||0}">${p.nome} - ${money(p.preco_venda)}</option>`).join('')}</select><input id="vQtd" type="number" value="1"><button onclick="addItem()">ADICIONAR</button><div id="cart"></div></div><div class="panel"><h3>TOTAL</h3><div class="kpi" id="totalVenda">R$ 0,00</div><select id="forma"><option>DINHEIRO</option><option>PIX</option><option>DÉBITO</option><option>CRÉDITO</option><option>CREDIÁRIO</option></select><button class="green" onclick="finalizarVenda()">FINALIZAR VENDA</button></div></div>`}
function addItem(){const s=$('vProd').selectedOptions[0],q=Number($('vQtd').value||1),p=Number(s.dataset.preco||0); cart.push({produto_id:s.value,descricao:s.dataset.nome,quantidade:q,valor_unitario:p,total:q*p}); renderCart()} function renderCart(){$('cart').innerHTML=simple(cart,['descricao','quantidade','valor_unitario','total']); $('totalVenda').textContent=money(cart.reduce((s,i)=>s+i.total,0))} async function finalizarVenda(){const total=cart.reduce((s,i)=>s+i.total,0); const venda=await api('/api/vendas',{method:'POST',body:JSON.stringify({cliente_nome:$('vCliente').value,total,subtotal:total,forma_pagamento:$('forma').value,status:$('forma').value==='CREDIÁRIO'?'ABERTO':'PAGO'})}); for(const i of cart) await api('/api/venda_itens',{method:'POST',body:JSON.stringify({...i,venda_id:venda.id})}); alert('VENDA FINALIZADA'); pdv()}
function financeiro(){crud('financeiro','FINANCEIRO',['descricao','tipo','categoria','valor','vencimento','pagamento','status','forma_pagamento','boleto_codigo','pix_chave','observacoes'])}
async function proLabore(){ $('content').innerHTML=`<div class="panel"><h3>PRÓ-LABORE / RETIRADAS</h3><div class="actions"><input id="plIni" type="date"><input id="plFim" type="date"><button onclick="resumoProLabore()">PESQUISAR CAIXA</button><button onclick="formCrud('pro_labore','NOVA RETIRADA',['descricao','valor','data_referencia','tipo'])">+ RETIRADA</button></div><div id="plResumo"></div><div id="plLista"></div></div>`; resumoProLabore()}
async function resumoProLabore(){const r=await api('/api/prolabore/resumo?inicio='+($('plIni')?.value||'')+'&fim='+($('plFim')?.value||'')); $('plResumo').innerHTML=`<div class="grid g4"><div class="panel"><h3>ENTRADAS</h3><div class="kpi">${money(r.entradas)}</div></div><div class="panel"><h3>SAÍDAS</h3><div class="kpi">${money(r.saidas)}</div></div><div class="panel"><h3>CAIXA TOTAL</h3><div class="kpi">${money(r.caixa)}</div></div><div class="panel"><h3>DISPONÍVEL</h3><div class="kpi">${money(r.disponivel)}</div></div></div>`; $('plLista').innerHTML=table(r.pro_labore,['descricao','valor','data_referencia','tipo'],'pro_labore')}
function campanhas(){$('content').innerHTML=`<div class="grid g2"><div class="panel"><h3>NOVA CAMPANHA WHATSAPP</h3><input id="campNome" class="upper" placeholder="NOME"><textarea id="campMsg" placeholder="MENSAGEM"></textarea><select id="campPublico"><option>CLIENTES</option><option>CLIENTES COM PEDIDO</option><option>ANIVERSARIANTES</option><option>DEVEDORES</option></select><input id="campData" type="datetime-local"><button onclick="salvarCampanha()">SALVAR / PROGRAMAR</button></div><div class="panel"><h3>CONEXÃO</h3><button class="green" onclick="abrirWhatsQr()">QR WHATSAPP</button><button class="secondary" onclick="configuracoes()">CONFIGURAR API</button><div id="campLista"></div></div></div>`;listarCampanhas()} async function salvarCampanha(){const r=await api('/api/whatsapp/campanhas/enviar',{method:'POST',body:JSON.stringify({nome:$('campNome').value,mensagem:$('campMsg').value,publico:$('campPublico').value,agendada_para:$('campData').value||null})}); alert(r.mensagem); listarCampanhas()} async function listarCampanhas(){try{const d=await api('/api/campanhas_whatsapp');$('campLista').innerHTML=table(d,['nome','publico','status','enviados','entregues'],'campanhas_whatsapp')}catch(e){}}
async function usuarios(){const d=await api('/api/usuarios'); $('content').innerHTML=`<div class="panel"><h3>USUÁRIOS / PERMISSÕES</h3><button onclick="formUsuario()">+ NOVO USUÁRIO</button>${table(d,['nome','usuario','perfil','ativo'],'usuarios')}</div>`}
function formUsuario(item={}){window.uId=item.id||null; const p=item.permissoes||{}; abrirModal(`<h2>USUÁRIO / PERMISSÕES</h2><div class="formgrid"><label>NOME<input id="u_nome" class="upper" value="${item.nome||''}"></label><label>USUÁRIO<input id="u_usuario" value="${item.usuario||''}"></label><label>SENHA<input id="u_senha" type="password"></label><label>PERFIL<select id="u_perfil"><option>admin</option><option>gerente</option><option>operador</option><option>consulta</option></select></label><label>ATIVO<select id="u_ativo"><option value="true">SIM</option><option value="false">NÃO</option></select></label></div><h3>PERMISSÕES</h3><label><input type="checkbox" id="perm_todas" ${p.todas?'checked':''}> TODAS</label><div class="formgrid">${modules.map(m=>`<label><input class="perm" type="checkbox" value="${m}" ${p[m]?'checked':''}> ${labels[m]}</label>`).join('')}</div><button onclick="salvarUsuario()">SALVAR</button>`)} async function salvarUsuario(){const permissoes={todas:$('perm_todas').checked}; document.querySelectorAll('.perm').forEach(c=>permissoes[c.value]=c.checked); const body={nome:$('u_nome').value,usuario:$('u_usuario').value,perfil:$('u_perfil').value,ativo:$('u_ativo').value==='true',permissoes}; if($('u_senha').value)body.senha=$('u_senha').value; if(window.uId)body.id=window.uId; await api('/api/usuarios',{method:'POST',body:JSON.stringify(body)}); fecharModal(); usuarios()}
function relatorios(){$('content').innerHTML=`<div class="grid g3"><div class="panel"><h3>VENDAS</h3><button onclick="crud('vendas','RELATÓRIO VENDAS',['cliente_nome','subtotal','desconto','total','forma_pagamento','status','created_at'])">ABRIR</button></div><div class="panel"><h3>COMPRAS</h3><button onclick="compras()">ABRIR</button></div><div class="panel"><h3>FINANCEIRO</h3><button onclick="financeiro()">ABRIR</button></div><div class="panel"><h3>PRODUÇÃO</h3><button onclick="producao()">ABRIR</button></div><div class="panel"><h3>ESTOQUE</h3><button onclick="produtos()">ABRIR</button></div><div class="panel"><h3>PRÓ-LABORE</h3><button onclick="proLabore()">ABRIR</button></div></div>`}
async function configuracoes(){let c={};try{c=await api('/api/config/whatsapp')}catch(e){} $('content').innerHTML=`<div class="panel"><h3>CONFIGURAÇÕES WHATSAPP / EVOLUTION API</h3><label>URL EVOLUTION<input id="cfgUrl" value="${c.url||''}"></label><label>API KEY<input id="cfgKey" value=""></label><label>INSTÂNCIA<input id="cfgInst" class="upper" value="${c.instance||'confeitaria'}"></label><button onclick="salvarConfigWhats()">SALVAR</button><button class="green" onclick="abrirWhatsQr()">TESTAR QR</button></div><div class="panel"><h3>APARÊNCIA</h3><p>FONTE POPPINS, TÍTULOS E CADASTROS EM UPPER CASE JÁ ATIVADOS.</p></div>`} async function salvarConfigWhats(){await api('/api/config/whatsapp',{method:'POST',body:JSON.stringify({url:$('cfgUrl').value,apiKey:$('cfgKey').value,instance:$('cfgInst').value})}); alert('CONFIGURAÇÃO SALVA')}
async function backup(){ $('content').innerHTML=`<div class="panel"><h3>BACKUP</h3><button onclick="baixarBackup()">EXPORTAR JSON</button><input id="restoreFile" type="file" accept="application/json"><button class="green" onclick="restaurarBackup()">RESTAURAR BACKUP</button></div>`} async function baixarBackup(){const d=await api('/api/backup/exportar'); const blob=new Blob([JSON.stringify(d,null,2)],{type:'application/json'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='backup-confeitaria-olitech.json'; a.click()} async function restaurarBackup(){const f=$('restoreFile').files[0]; if(!f)return alert('SELECIONE O JSON'); const fd=new FormData(); fd.append('backup',f); const r=await fetch('/api/backup/restaurar',{method:'POST',body:fd}); const j=await r.json(); if(!j.ok)return alert(j.error); alert('BACKUP RESTAURADO')}
function abrirModal(html){$('modalContent').innerHTML=html;$('modal').classList.remove('hidden')} function fecharModal(){$('modal').classList.add('hidden');$('modalContent').innerHTML=''} function abrirSobre(){abrirModal('<h2>SOBRE O SISTEMA</h2><img class="sobre-img" src="/img/sobre-olitech.png"><p>SISTEMA DESENVOLVIDO POR OLITECH - THIAGO LUCAS DE OLIVEIRA EM CONJUNTO COM O CHATGPT.</p>')}
async function abrirWhatsQr(){try{const r=await api('/api/whatsapp/qrcode');let img=r.qrcode||''; if(img&&!img.startsWith('data:')&&img.length>200) img='data:image/png;base64,'+img; abrirModal(`<h2>CONECTAR WHATSAPP</h2><p>${r.instrucoes}</p>${img?`<img src="${img}" class="sobre-img">`:`<pre>${JSON.stringify(r.raw||r,null,2)}</pre>`}`)}catch(e){abrirModal(`<h2>ERRO WHATSAPP</h2><p>${e.message}</p><button onclick="fecharModal();configuracoes()">ABRIR CONFIGURAÇÕES</button>`)} }


// ===== V4.3 MELHORIAS SOLICITADAS =====
function vendasTabela(rows){return `<div style="overflow:auto"><table><thead><tr><th>CLIENTE</th><th>TOTAL</th><th>FORMA</th><th>DESCONTO</th><th>JUROS</th><th>STATUS</th><th>DATA</th><th>AÇÕES</th></tr></thead><tbody>${(rows||[]).map(v=>`<tr><td>${fmt('cliente_nome',v.cliente_nome)}</td><td>${money(v.total)}</td><td>${fmt('forma_pagamento',v.forma_pagamento)}</td><td>${money(v.desconto)}</td><td>${money(v.juros)}</td><td>${fmt('status',v.status)}</td><td>${fmt('created_at',v.created_at)}</td><td><button class="secondary" onclick='formCrud("vendas","EDITAR VENDA",["cliente_nome","subtotal","desconto","juros","total","forma_pagamento","status","observacoes"],${JSON.stringify(v).replace(/'/g,'&#39;')})'>EDITAR</button> <button class="red" onclick="cancelarVenda('${v.id}')">CANCELAR</button></td></tr>`).join('')}</tbody></table></div>`}
async function cancelarVenda(id){const motivo=prompt('MOTIVO DO CANCELAMENTO:','CANCELAMENTO MANUAL'); if(!motivo)return; await api('/api/vendas/cancelar/'+id,{method:'POST',body:JSON.stringify({motivo})}); alert('VENDA CANCELADA'); pdv();}
async function pdv(){const [prods,formas,vendas]=await Promise.all([api('/api/produtos'),api('/api/formas-pagamento'),api('/api/vendas')]); cart=[]; $('content').innerHTML=`<div class="grid g2"><div class="panel"><h3>PDV / NOVA VENDA</h3><input id="vCliente" class="upper" value="CONSUMIDOR" placeholder="CLIENTE"><select id="vProd">${prods.map(p=>`<option value="${p.id}" data-nome="${p.nome}" data-preco="${p.preco_venda||0}">${p.nome} - ${money(p.preco_venda)}</option>`).join('')}</select><input id="vQtd" type="number" value="1"><button onclick="addItem()">ADICIONAR</button><div id="cart"></div></div><div class="panel"><h3>TOTAL</h3><label>DESCONTO R$<input id="vDesc" type="number" value="0" oninput="renderCart()"></label><label>JUROS R$<input id="vJuros" type="number" value="0" oninput="renderCart()"></label><div class="kpi" id="totalVenda">R$ 0,00</div><select id="forma">${formas.map(f=>`<option>${f}</option>`).join('')}</select><button class="green" onclick="finalizarVenda()">FINALIZAR VENDA</button></div></div><div class="panel"><h3>VENDAS / EDITAR / CANCELAR</h3>${vendasTabela(vendas)}</div>`}
function renderCart(){const subtotal=cart.reduce((s,i)=>s+i.total,0), desc=Number($('vDesc')?.value||0), juros=Number($('vJuros')?.value||0); $('cart').innerHTML=simple(cart,['descricao','quantidade','valor_unitario','total']); $('totalVenda').textContent=money(subtotal-desc+juros)}
async function finalizarVenda(){const subtotal=cart.reduce((s,i)=>s+i.total,0), desconto=Number($('vDesc').value||0), juros=Number($('vJuros').value||0), total=subtotal-desconto+juros; const venda=await api('/api/vendas',{method:'POST',body:JSON.stringify({cliente_nome:$('vCliente').value,total,subtotal,desconto,juros,forma_pagamento:$('forma').value,status:$('forma').value==='CREDIÁRIO'?'ABERTO':'PAGO'})}); for(const i of cart) await api('/api/venda_itens',{method:'POST',body:JSON.stringify({...i,venda_id:venda.id})}); alert('VENDA FINALIZADA'); pdv()}
function financeiro(){crud('financeiro','FINANCEIRO',['descricao','nome_empresa','cpf_cnpj','tipo','categoria','valor','vencimento','pagamento','status','forma_pagamento','boleto_codigo','pix_chave','observacoes'])}
async function clientes(){const d=await api('/api/clientes?busca='+encodeURIComponent($('busca')?.value||'')); $('content').innerHTML=`<div class="panel"><div class="actions"><input id="busca" placeholder="PESQUISAR CLIENTE" oninput="if(this.value.length>1||!this.value) clientes()" value="${$('busca')?.value||''}"><button onclick='formCrud("clientes","CLIENTES",["nome","telefone","whatsapp","email","cpf_cnpj","rua","numero","complemento","bairro","cidade","estado","cep","observacoes"])'>+ NOVO</button><button class="green" onclick="exportarClientes()">EXPORTAR</button><input id="impClientes" type="file" accept=".csv,text/csv"><button onclick="importarClientes()">IMPORTAR CELULAR/CSV</button></div>${table(d,['nome','telefone','whatsapp','email','cidade','estado'],'clientes')}</div>`}
function exportarClientes(){location.href='/api/clientes/exportar'}
async function importarClientes(){const f=$('impClientes').files[0]; if(!f)return alert('SELECIONE CSV DOS CONTATOS'); const fd=new FormData(); fd.append('arquivo',f); const r=await fetch('/api/clientes/importar',{method:'POST',body:fd}).then(r=>r.json()); if(!r.ok)return alert(r.error); alert('IMPORTADOS: '+r.data.importados); clientes();}
async function campanhas(){const clientes=await api('/api/clientes'); $('content').innerHTML=`<div class="grid g2"><div class="panel"><h3>NOVA CAMPANHA WHATSAPP</h3><input id="campNome" class="upper" placeholder="NOME DA CAMPANHA"><textarea id="campMsg" placeholder="MENSAGEM DA CAMPANHA"></textarea><label>DESTINO<select id="campDestino" onchange="$('campClienteBox').style.display=this.value==='UM'?'block':'none'"><option value="TODOS">TODOS OS CLIENTES CADASTRADOS</option><option value="UM">SELECIONAR 1 CLIENTE</option></select></label><label id="campClienteBox" style="display:none">CLIENTE<select id="campCliente"><option value="">SELECIONE</option>${clientes.map(c=>`<option value="${c.id}">${c.nome} - ${c.whatsapp||c.telefone||''}</option>`).join('')}</select></label><label>ANEXAR IMAGEM OU VÍDEO<input id="campAnexo" type="file" accept="image/*,video/*"></label><label>AGENDAR PARA<input id="campData" type="datetime-local"></label><label><input id="campAgora" type="checkbox" checked> ENVIAR AGORA PELO SISTEMA</label><button class="green" onclick="enviarCampanhaCompleta()">ENVIAR / PROGRAMAR</button></div><div class="panel"><h3>CAMPANHAS ENVIADAS</h3><p>A CONFIGURAÇÃO DA API DO WHATSAPP FICA SOMENTE NA ABA CONFIGURAÇÕES.</p><div id="campLista"></div></div></div>`; listarCampanhas()}
async function enviarCampanhaCompleta(){const fd=new FormData(); fd.append('nome',$('campNome').value); fd.append('mensagem',$('campMsg').value); fd.append('publico','TODOS'); fd.append('enviar_agora',$('campAgora').checked); fd.append('agendada_para',$('campData').value||''); if($('campDestino').value==='UM') fd.append('cliente_id',$('campCliente').value); if($('campAnexo').files[0]) fd.append('anexo',$('campAnexo').files[0]); const r=await fetch('/api/whatsapp/campanhas/enviar-completo',{method:'POST',body:fd}).then(r=>r.json()); if(!r.ok)return alert(r.error); alert(r.data.mensagem); listarCampanhas();}
async function configuracoes(){let c={}, emp={}, formas=[];try{c=await api('/api/config/whatsapp'); emp=await api('/api/config/empresa'); formas=await api('/api/formas-pagamento')}catch(e){} $('content').innerHTML=`<div class="grid g2"><div class="panel"><h3>CONFIGURAÇÕES WHATSAPP / EVOLUTION API</h3><label>URL EVOLUTION<input id="cfgUrl" value="${c.url||''}"></label><label>API KEY<input id="cfgKey" value=""></label><label>INSTÂNCIA<input id="cfgInst" class="upper" value="${c.instance||'confeitaria'}"></label><button onclick="salvarConfigWhats()">SALVAR WHATSAPP</button><button class="green" onclick="abrirWhatsQr()">TESTAR QR</button></div><div class="panel"><h3>EMPRESA / LOGO</h3><label>NOME DA EMPRESA<input id="empNome" class="upper" value="${emp.nome||'CONFEITARIA OLITECH'}"></label><label>CNPJ<input id="empCnpj" value="${emp.cnpj||''}"></label><label>WHATSAPP<input id="empWhats" value="${emp.whatsapp||''}"></label><label>LOGO<input id="empLogo" type="file" accept="image/*"></label>${emp.logo_data?`<img class="sobre-img" src="${emp.logo_data}">`:''}<button class="green" onclick="salvarEmpresa()">SALVAR EMPRESA / LOGO</button></div></div><div class="panel"><h3>TIPOS DE PAGAMENTO</h3><p>EDITE UM POR LINHA. PODE USAR DESCONTO/JUROS NA VENDA.</p><textarea id="formasPag">${(formas||[]).join('\n')}</textarea><button onclick="salvarFormasPagamento()">SALVAR TIPOS DE PAGAMENTO</button></div><div class="panel"><h3>APARÊNCIA</h3><p>FONTE POPPINS, TÍTULOS E CADASTROS EM UPPER CASE ATIVADOS.</p></div>`}
async function salvarEmpresa(){const fd=new FormData(); fd.append('nome',$('empNome').value); fd.append('cnpj',$('empCnpj').value); fd.append('whatsapp',$('empWhats').value); if($('empLogo').files[0])fd.append('logo',$('empLogo').files[0]); const r=await fetch('/api/config/empresa',{method:'POST',body:fd}).then(r=>r.json()); if(!r.ok)return alert(r.error); alert('EMPRESA / LOGO SALVA')}
async function salvarFormasPagamento(){const formas=$('formasPag').value.split(/\n/).map(x=>x.trim()).filter(Boolean); await api('/api/formas-pagamento',{method:'POST',body:JSON.stringify({formas})}); alert('FORMAS DE PAGAMENTO SALVAS')}
function userTable(rows){return `<div style="overflow:auto"><table><thead><tr><th>NOME</th><th>USUÁRIO</th><th>PERFIL</th><th>ATIVO</th><th>AÇÕES</th></tr></thead><tbody>${(rows||[]).map(u=>`<tr><td>${u.nome}</td><td>${u.usuario}</td><td>${u.perfil}</td><td>${u.ativo?'SIM':'NÃO'}</td><td><button class="secondary" onclick='formUsuario(${JSON.stringify(u).replace(/'/g,'&#39;')})'>EDITAR PERMISSÕES</button> <button class="red" onclick="del('usuarios','${u.id}')">EXCLUIR</button></td></tr>`).join('')}</tbody></table></div>`}
async function usuarios(){const d=await api('/api/usuarios'); $('content').innerHTML=`<div class="panel"><h3>USUÁRIOS / PERMISSÕES POR FUNÇÃO</h3><button onclick="formUsuario()">+ NOVO USUÁRIO</button>${userTable(d)}</div>`}
async function imprimirProducao(){const r=window.lastCalc;if(!r)return alert('CALCULE PRIMEIRO'); let emp={};try{emp=await api('/api/config/empresa')}catch(e){} const logo=emp.logo_data?`<img src="${emp.logo_data}" style="max-height:90px">`:''; const html=`<div class="print-area">${logo}<h1>FICHA DE PRODUÇÃO - ${emp.nome||'CONFEITARIA OLITECH'}</h1><h2>${r.receita.nome}</h2><p>PESO DESEJADO: ${r.peso_desejado} | CUSTO: ${money(r.custo)} | VENDA SUGERIDA: ${money(r.venda)}</p>${simple(r.detalhes,['produto','quantidade','unidade','custo_unitario','custo_total'])}<h3>MODO DE PREPARO</h3><p>${r.receita.modo_preparo||''}</p><br><p>RESPONSÁVEL: __________________________</p></div>`; const w=open('','_blank'); w.document.write(html); w.document.close(); w.print()}

layout();

// ===== V4.6 RECEITAS COM INGREDIENTES, IMPRESSÃO COM/SEM VALOR E PERMISSÃO =====
function canVerValoresReceita(){return USER?.perfil==='admin'||USER?.permissoes?.todas||USER?.permissoes?.ver_valores_receitas||USER?.permissoes?.valores}
function esc(v){return String(v??'').replace(/[&<>"]/g,s=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[s]))}
async function receitas(){
  const busca=encodeURIComponent($('busca')?.value||'');
  const d=await api('/api/receitas?busca='+busca);
  $('content').innerHTML=`<div class="panel"><div class="actions"><input id="busca" placeholder="PESQUISAR RECEITA" oninput="if(this.value.length>1||!this.value) receitas()" value="${esc($('busca')?.value||'')}"><button onclick="formReceita()">+ NOVA RECEITA</button></div><div style="overflow:auto"><table><thead><tr><th>NOME</th><th>CATEGORIA</th><th>BASE</th><th>RENDIMENTO</th><th>CUSTO</th><th>VENDA</th><th>AÇÕES</th></tr></thead><tbody>${d.map(r=>`<tr><td>${esc(r.nome)}</td><td>${esc(r.categoria)}</td><td>${esc(r.peso_base)} ${esc(r.unidade_base)}</td><td>${esc(r.rendimento)}</td><td>${canVerValoresReceita()?money(r.custo_total):'***'}</td><td>${canVerValoresReceita()?money(r.preco_venda):'***'}</td><td><button class="secondary" onclick='formReceita(${JSON.stringify(r).replace(/'/g,"&#39;")})'>EDITAR</button> <button onclick="ingredientesReceita('${r.id}')">PRODUTOS</button> <button class="green" onclick="imprimirReceita('${r.id}',false)">IMPRIMIR SEM VALOR</button> ${canVerValoresReceita()?`<button onclick="imprimirReceita('${r.id}',true)">IMPRIMIR COM VALOR</button>`:''} <button class="red" onclick="del('receitas','${r.id}')">EXCLUIR</button></td></tr>`).join('')}</tbody></table></div></div>`;
}
function formReceita(item={}){
  window.receitaEditId=item.id||null;
  abrirModal(`<h2>RECEITA</h2><div class="formgrid"><label>NOME<input id="r_nome" class="upper" value="${esc(item.nome)}"></label><label>CATEGORIA<input id="r_categoria" class="upper" value="${esc(item.categoria)}"></label><label>PESO / BASE<input id="r_peso_base" type="number" step="0.001" value="${item.peso_base||1}"></label><label>UNIDADE BASE<input id="r_unidade_base" class="upper" value="${esc(item.unidade_base||'KG')}"></label><label>RENDIMENTO<input id="r_rendimento" class="upper" value="${esc(item.rendimento)}"></label><label>MARGEM %<input id="r_margem_percentual" type="number" step="0.01" value="${item.margem_percentual||100}"></label><label>PREÇO VENDA<input id="r_preco_venda" type="number" step="0.01" value="${item.preco_venda||0}"></label><label class="full">MODO DE PREPARO<textarea id="r_modo_preparo" class="upper">${esc(item.modo_preparo)}</textarea></label></div><button onclick="salvarReceita()">SALVAR RECEITA</button>`)
}
async function salvarReceita(){
  const body={nome:$('r_nome').value,categoria:$('r_categoria').value,peso_base:$('r_peso_base').value,unidade_base:$('r_unidade_base').value,rendimento:$('r_rendimento').value,margem_percentual:$('r_margem_percentual').value,preco_venda:$('r_preco_venda').value,modo_preparo:$('r_modo_preparo').value};
  if(window.receitaEditId) body.id=window.receitaEditId;
  const r=await api('/api/receitas',{method:'POST',body:JSON.stringify(body)});
  fecharModal(); await receitas(); ingredientesReceita(r.id);
}
async function ingredientesReceita(receitaId){
  const [receitasLista, produtos, itensAll]=await Promise.all([api('/api/receitas'), api('/api/produtos'), api('/api/receita_itens')]);
  const receita=receitasLista.find(r=>r.id===receitaId)||{};
  const itens=(itensAll||[]).filter(i=>i.receita_id===receitaId);
  const prodMap=Object.fromEntries(produtos.map(p=>[p.id,p]));
  const total=itens.reduce((s,i)=>s+Number(i.quantidade||0)*Number(i.custo_unitario||prodMap[i.produto_id]?.custo_medio||prodMap[i.produto_id]?.custo_unitario||0),0);
  const venda=Number(receita.preco_venda||0)||total*(1+Number(receita.margem_percentual||0)/100);
  abrirModal(`<h2>PRODUTOS DA RECEITA: ${esc(receita.nome)}</h2><p>Cadastre aqui os ingredientes/produtos usados. Exemplo: <b>100 GR de farinha</b>, <b>1 L de leite</b>.</p><div class="formgrid"><label>PRODUTO<select id="ri_produto" onchange="preencherProdutoReceita()"><option value="">SELECIONE</option>${produtos.map(p=>`<option value="${p.id}">${esc(p.nome)} - ${esc(p.unidade)} - ${money(p.custo_medio||p.custo_unitario)}</option>`).join('')}</select></label><label>QUANTIDADE<input id="ri_qtd" type="number" step="0.001" value="1"></label><label>UNIDADE<input id="ri_unidade" class="upper" value="UN"></label><label>CUSTO UNITÁRIO<input id="ri_custo" type="number" step="0.0001" value="0"></label></div><button class="green" onclick="addIngredienteReceita('${receitaId}')">ADICIONAR PRODUTO</button><hr><div style="overflow:auto"><table><thead><tr><th>PRODUTO</th><th>QUANTIDADE</th><th>UNIDADE</th>${canVerValoresReceita()?'<th>CUSTO UNIT.</th><th>CUSTO TOTAL</th>':''}<th>AÇÕES</th></tr></thead><tbody>${itens.map(i=>{const p=prodMap[i.produto_id]||{}; const cu=Number(i.custo_unitario||p.custo_medio||p.custo_unitario||0); const ct=Number(i.quantidade||0)*cu; return `<tr><td>${esc(p.nome||i.descricao)}</td><td>${esc(i.quantidade)}</td><td>${esc(i.unidade||p.unidade)}</td>${canVerValoresReceita()?`<td>${money(cu)}</td><td>${money(ct)}</td>`:''}<td><button class="red" onclick="delIngredienteReceita('${i.id}','${receitaId}')">EXCLUIR</button></td></tr>`}).join('')}</tbody></table></div>${canVerValoresReceita()?`<div class="kpi">CUSTO DA RECEITA: ${money(total)}<br>VENDA SUGERIDA: ${money(venda)}</div>`:''}<div class="actions"><button class="green" onclick="imprimirReceita('${receitaId}',false)">IMPRIMIR SEM VALOR</button>${canVerValoresReceita()?`<button onclick="imprimirReceita('${receitaId}',true)">IMPRIMIR COM VALOR</button>`:''}<button class="secondary" onclick="fecharModal()">FECHAR</button></div>`);
  window.receitaProdutos=produtos;
}
function preencherProdutoReceita(){const p=(window.receitaProdutos||[]).find(x=>x.id===$('ri_produto').value); if(!p)return; $('ri_unidade').value=p.unidade||'UN'; $('ri_custo').value=Number(p.custo_medio||p.custo_unitario||0).toFixed(4)}
async function addIngredienteReceita(receitaId){const p=(window.receitaProdutos||[]).find(x=>x.id===$('ri_produto').value); if(!p)return alert('SELECIONE O PRODUTO'); await api('/api/receita_itens',{method:'POST',body:JSON.stringify({receita_id:receitaId,produto_id:p.id,descricao:p.nome,quantidade:$('ri_qtd').value,unidade:$('ri_unidade').value,custo_unitario:$('ri_custo').value})}); await atualizarCustoReceita(receitaId); ingredientesReceita(receitaId)}
async function delIngredienteReceita(id,receitaId){if(!confirm('EXCLUIR PRODUTO DA RECEITA?'))return; await api('/api/receita_itens/'+id,{method:'DELETE'}); await atualizarCustoReceita(receitaId); ingredientesReceita(receitaId)}
async function atualizarCustoReceita(receitaId){try{const r=await api('/api/receitas/calcular',{method:'POST',body:JSON.stringify({receita_id:receitaId,peso_base:1,peso_desejado:1})}); await api('/api/receitas',{method:'POST',body:JSON.stringify({id:receitaId,custo_total:r.custo,preco_venda:r.venda,margem_percentual:r.margem})})}catch(e){console.warn(e)}}
async function imprimirReceita(receitaId,comValor){
  if(comValor&&!canVerValoresReceita())return alert('SEU USUÁRIO NÃO TEM PERMISSÃO PARA IMPRIMIR VALORES.');
  const [receitasLista, produtos, itensAll]=await Promise.all([api('/api/receitas'), api('/api/produtos'), api('/api/receita_itens')]); let emp={};try{emp=await api('/api/config/empresa')}catch(e){}
  const receita=receitasLista.find(r=>r.id===receitaId)||{}; const itens=(itensAll||[]).filter(i=>i.receita_id===receitaId); const prodMap=Object.fromEntries(produtos.map(p=>[p.id,p]));
  const rows=itens.map(i=>{const p=prodMap[i.produto_id]||{}; const cu=Number(i.custo_unitario||p.custo_medio||p.custo_unitario||0); return {...i,nome:p.nome||i.descricao,unidade:i.unidade||p.unidade,custo_unitario:cu,custo_total:Number(i.quantidade||0)*cu}});
  const custo=rows.reduce((s,i)=>s+i.custo_total,0); const venda=Number(receita.preco_venda||0)||custo*(1+Number(receita.margem_percentual||0)/100); const logo=emp.logo_data?`<img src="${emp.logo_data}" style="max-height:85px">`:'';
  const cols=comValor?['PRODUTO','QUANTIDADE','UNIDADE','CUSTO UNIT.','CUSTO TOTAL']:['PRODUTO','QUANTIDADE','UNIDADE'];
  const body=rows.map(i=>`<tr><td>${esc(i.nome)}</td><td>${esc(i.quantidade)}</td><td>${esc(i.unidade)}</td>${comValor?`<td>${money(i.custo_unitario)}</td><td>${money(i.custo_total)}</td>`:''}</tr>`).join('');
  const html=`<html><head><title>Receita</title><style>body{font-family:Arial;padding:24px;color:#111}table{width:100%;border-collapse:collapse;margin-top:12px}th,td{border:1px solid #bbb;padding:8px;text-align:left}th{background:#eee}.top{display:flex;justify-content:space-between;align-items:flex-start}.assin{margin-top:35px}</style></head><body><div class="top"><div>${logo}<h1>${esc(emp.nome||'CONFEITARIA OLITECH')}</h1><h2>FICHA DE RECEITA ${comValor?'COM VALORES':'SEM VALORES'}</h2></div><div>DATA: ${new Date().toLocaleDateString('pt-BR')}</div></div><h2>${esc(receita.nome)}</h2><p><b>Categoria:</b> ${esc(receita.categoria)} &nbsp; <b>Base:</b> ${esc(receita.peso_base)} ${esc(receita.unidade_base)} &nbsp; <b>Rendimento:</b> ${esc(receita.rendimento)}</p>${comValor?`<p><b>Custo total:</b> ${money(custo)} &nbsp; <b>Venda sugerida:</b> ${money(venda)} &nbsp; <b>Margem:</b> ${esc(receita.margem_percentual)}%</p>`:''}<table><thead><tr>${cols.map(c=>`<th>${c}</th>`).join('')}</tr></thead><tbody>${body}</tbody></table><h3>MODO DE PREPARO</h3><p>${esc(receita.modo_preparo).replace(/\n/g,'<br>')}</p><p class="assin">Responsável: ____________________________________________</p></body></html>`;
  const w=open('','_blank'); w.document.write(html); w.document.close(); w.focus(); w.print();
}

// substitui cadastro de usuários para liberar permissão específica de imprimir valores das receitas
function formUsuario(item={}){window.uId=item.id||null; const p=item.permissoes||{}; abrirModal(`<h2>USUÁRIO / PERMISSÕES</h2><div class="formgrid"><label>NOME<input id="u_nome" class="upper" value="${esc(item.nome)}"></label><label>USUÁRIO<input id="u_usuario" value="${esc(item.usuario)}"></label><label>SENHA<input id="u_senha" type="password"></label><label>PERFIL<select id="u_perfil"><option ${item.perfil==='admin'?'selected':''}>admin</option><option ${item.perfil==='gerente'?'selected':''}>gerente</option><option ${item.perfil==='operador'?'selected':''}>operador</option><option ${item.perfil==='consulta'?'selected':''}>consulta</option></select></label><label>ATIVO<select id="u_ativo"><option value="true" ${item.ativo!==false?'selected':''}>SIM</option><option value="false" ${item.ativo===false?'selected':''}>NÃO</option></select></label></div><h3>PERMISSÕES</h3><label><input type="checkbox" id="perm_todas" ${p.todas?'checked':''}> TODAS</label><label><input type="checkbox" id="perm_ver_valores_receitas" ${p.ver_valores_receitas?'checked':''}> VER / IMPRIMIR VALORES DAS RECEITAS</label><div class="formgrid">${modules.map(m=>`<label><input class="perm" type="checkbox" value="${m}" ${p[m]?'checked':''}> ${labels[m]}</label>`).join('')}</div><button onclick="salvarUsuario()">SALVAR</button>`)}
async function salvarUsuario(){const permissoes={todas:$('perm_todas').checked,ver_valores_receitas:$('perm_ver_valores_receitas').checked}; document.querySelectorAll('.perm').forEach(c=>permissoes[c.value]=c.checked); const body={nome:$('u_nome').value,usuario:$('u_usuario').value,perfil:$('u_perfil').value,ativo:$('u_ativo').value==='true',permissoes}; if($('u_senha').value)body.senha=$('u_senha').value; if(window.uId)body.id=window.uId; await api('/api/usuarios',{method:'POST',body:JSON.stringify(body)}); fecharModal(); usuarios()}


// ===== V5.0 - PAGAMENTOS EM MODAL, PDV COM DESCONTO/JUROS AUTOMÁTICO E PEDIDOS COM VÁRIOS ITENS =====
function parseMoney(v){return Number(String(v||0).replace(',','.'))||0}
function formaNome(f){return typeof f==='string'?f:(f?.nome||'DINHEIRO')}
async function getFormasAvancadas(){try{return await api('/api/formas-pagamento-v2')}catch(e){let f=await api('/api/formas-pagamento');return (f||[]).map(x=>({nome:x,tipo:'NENHUM',percentual:0}))}}
function aplicarFormaPagamento(prefix, formas){
  const sel=$(prefix+'Forma'); if(!sel)return;
  const forma=(formas||window.formasPagamentoAtual||[]).find(f=>formaNome(f)===sel.value)||{tipo:'NENHUM',percentual:0};
  const subtotal=prefix==='v'?cart.reduce((s,i)=>s+i.total,0):pedidoCart.reduce((s,i)=>s+i.total,0);
  const perc=parseMoney(forma.percentual);
  const desc=(forma.tipo||'').includes('DESCONTO')?subtotal*perc/100:0;
  const juros=(forma.tipo||'').includes('JUROS')?subtotal*perc/100:0;
  if($(prefix+'DescAuto')) $(prefix+'DescAuto').value=desc.toFixed(2);
  if($(prefix+'JurosAuto')) $(prefix+'JurosAuto').value=juros.toFixed(2);
  if(prefix==='v') renderCart(); else renderPedidoCart();
}
function totalComPagamentos(prefix, subtotal){
  const descAuto=parseMoney($(prefix+'DescAuto')?.value), descManual=parseMoney($(prefix+'DescManual')?.value||$(prefix+'Desc')?.value), jurosAuto=parseMoney($(prefix+'JurosAuto')?.value), jurosManual=parseMoney($(prefix+'JurosManual')?.value||$(prefix+'Juros')?.value);
  return {desconto:descAuto+descManual, juros:jurosAuto+jurosManual, total:subtotal-descAuto-descManual+jurosAuto+jurosManual};
}
async function abrirModalFormasPagamento(){
  const formas=await getFormasAvancadas(); window.editFormas=JSON.parse(JSON.stringify(formas));
  abrirModal(`<h2>TIPOS DE PAGAMENTO</h2><p>Cadastre desconto ou juros automático por forma de pagamento.</p><div id="formasEditor"></div><button class="green" onclick="novaFormaPagamento()">+ NOVA FORMA</button> <button onclick="salvarFormasPagamentoAvancadas()">SALVAR</button> <button class="secondary" onclick="fecharModal()">FECHAR</button>`);
  renderFormasEditor();
}
function renderFormasEditor(){
  $('formasEditor').innerHTML=`<div style="overflow:auto"><table><thead><tr><th>NOME</th><th>TIPO</th><th>%</th><th>AÇÕES</th></tr></thead><tbody>${(window.editFormas||[]).map((f,i)=>`<tr><td><input id="fp_nome_${i}" class="upper" value="${esc(f.nome)}"></td><td><select id="fp_tipo_${i}"><option ${f.tipo==='NENHUM'?'selected':''}>NENHUM</option><option ${f.tipo==='DESCONTO'?'selected':''}>DESCONTO</option><option ${f.tipo==='JUROS'?'selected':''}>JUROS</option></select></td><td><input id="fp_perc_${i}" type="number" step="0.01" value="${f.percentual||0}"></td><td><button class="red" onclick="window.editFormas.splice(${i},1);renderFormasEditor()">EXCLUIR</button></td></tr>`).join('')}</tbody></table></div>`;
}
function novaFormaPagamento(){window.editFormas=window.editFormas||[]; window.editFormas.push({nome:'NOVA FORMA',tipo:'NENHUM',percentual:0}); renderFormasEditor()}
async function salvarFormasPagamentoAvancadas(){
  const formas=(window.editFormas||[]).map((f,i)=>({nome:$('fp_nome_'+i).value,tipo:$('fp_tipo_'+i).value,percentual:parseMoney($('fp_perc_'+i).value)}));
  await api('/api/formas-pagamento-v2',{method:'POST',body:JSON.stringify({formas})}); alert('FORMAS DE PAGAMENTO SALVAS'); fecharModal(); configuracoes();
}
async function configuracoes(){let c={}, emp={}, formas=[];try{c=await api('/api/config/whatsapp'); emp=await api('/api/config/empresa'); formas=await getFormasAvancadas()}catch(e){} $('content').innerHTML=`<div class="grid g2"><div class="panel"><h3>CONFIGURAÇÕES WHATSAPP / EVOLUTION API</h3><label>URL EVOLUTION<input id="cfgUrl" value="${c.url||''}"></label><label>API KEY<input id="cfgKey" value=""></label><label>INSTÂNCIA<input id="cfgInst" class="upper" value="${c.instance||'confeitaria'}"></label><button onclick="salvarConfigWhats()">SALVAR WHATSAPP</button><button class="green" onclick="abrirWhatsQr()">TESTAR QR</button></div><div class="panel"><h3>EMPRESA / LOGO</h3><label>NOME DA EMPRESA<input id="empNome" class="upper" value="${emp.nome||'CONFEITARIA OLITECH'}"></label><label>CNPJ<input id="empCnpj" value="${emp.cnpj||''}"></label><label>WHATSAPP<input id="empWhats" value="${emp.whatsapp||''}"></label><label>LOGO<input id="empLogo" type="file" accept="image/*"></label>${emp.logo_data?`<img class="sobre-img" src="${emp.logo_data}">`:''}<button class="green" onclick="salvarEmpresa()">SALVAR EMPRESA / LOGO</button></div></div><div class="panel"><h3>TIPOS DE PAGAMENTO</h3><p>Exemplo: DINHEIRO desconto 5%, PIX desconto 5%, CARTÃO CRÉDITO juros 15%.</p>${simple(formas,['nome','tipo','percentual'])}<button onclick="abrirModalFormasPagamento()">CADASTRAR / EDITAR / EXCLUIR TIPOS</button></div><div class="panel"><h3>APARÊNCIA</h3><p>FONTE POPPINS, TÍTULOS E CADASTROS EM UPPER CASE ATIVADOS.</p></div>`}
async function pdv(){const [prods,formas,vendas]=await Promise.all([api('/api/produtos'),getFormasAvancadas(),api('/api/vendas')]); window.formasPagamentoAtual=formas; cart=[]; $('content').innerHTML=`<div class="grid g2"><div class="panel"><h3>PDV / NOVA VENDA</h3><input id="vCliente" class="upper" value="CONSUMIDOR" placeholder="CLIENTE"><select id="vProd">${prods.map(p=>`<option value="${p.id}" data-nome="${p.nome}" data-preco="${p.preco_venda||0}">${p.nome} - ${money(p.preco_venda)}</option>`).join('')}</select><input id="vQtd" type="number" value="1"><button onclick="addItem();aplicarFormaPagamento('v')">ADICIONAR</button><div id="cart"></div></div><div class="panel"><h3>TOTAL</h3><label>FORMA DE PAGAMENTO<select id="vForma" onchange="aplicarFormaPagamento('v')">${formas.map(f=>`<option ${formaNome(f)==='DINHEIRO'?'selected':''}>${formaNome(f)}</option>`).join('')}</select></label><label>DESCONTO AUTOMÁTICO R$<input id="vDescAuto" type="number" value="0" readonly></label><label>JUROS AUTOMÁTICO R$<input id="vJurosAuto" type="number" value="0" readonly></label><label>DESCONTO MANUAL R$<input id="vDescManual" type="number" value="0" oninput="renderCart()"></label><label>JUROS MANUAL R$<input id="vJurosManual" type="number" value="0" oninput="renderCart()"></label><div class="kpi" id="totalVenda">R$ 0,00</div><label><input id="vBaixarEstoque" type="checkbox" checked> BAIXAR ESTOQUE AO FINALIZAR</label><button class="green" onclick="finalizarVenda()">FINALIZAR VENDA</button></div></div><div class="panel"><h3>VENDAS / EDITAR / CANCELAR</h3>${vendasTabela(vendas)}</div>`; aplicarFormaPagamento('v')}
function renderCart(){const subtotal=cart.reduce((s,i)=>s+i.total,0); const t=totalComPagamentos('v',subtotal); if($('cart'))$('cart').innerHTML=simple(cart,['descricao','quantidade','valor_unitario','total']); if($('totalVenda'))$('totalVenda').textContent=money(t.total)}
async function finalizarVenda(){const subtotal=cart.reduce((s,i)=>s+i.total,0), t=totalComPagamentos('v',subtotal); const venda=await api('/api/vendas',{method:'POST',body:JSON.stringify({cliente_nome:$('vCliente').value,total:t.total,subtotal,desconto:t.desconto,juros:t.juros,forma_pagamento:$('vForma').value,status:'PAGO'})}); for(const i of cart){await api('/api/venda_itens',{method:'POST',body:JSON.stringify({...i,venda_id:venda.id})}); if($('vBaixarEstoque').checked&&i.produto_id){try{const ps=await api('/api/produtos'); const p=ps.find(x=>x.id===i.produto_id); if(p) await api('/api/produtos',{method:'POST',body:JSON.stringify({id:p.id,estoque_atual:parseMoney(p.estoque_atual)-parseMoney(i.quantidade)})})}catch(e){console.warn(e)}}} alert('VENDA FINALIZADA'); pdv()}
let pedidoCart=[];
function pedidosTabela(rows){return `<div style="overflow:auto"><table><thead><tr><th>CLIENTE</th><th>DATA</th><th>HORA</th><th>ENTREGA/BUSCA</th><th>TOTAL</th><th>FORMA</th><th>STATUS</th><th>AÇÕES</th></tr></thead><tbody>${(rows||[]).map(p=>`<tr><td>${esc(p.cliente_nome)}</td><td>${fmt('data_entrega',p.data_entrega)}</td><td>${esc(p.hora_entrega)}</td><td>${esc(p.entrega_tipo||'ENTREGA')}</td><td>${money(p.total)}</td><td>${esc(p.forma_pagamento)}</td><td>${esc(p.status)}</td><td><button class="secondary" onclick="formPedido('${p.id}')">EDITAR</button> <button onclick="baixarPedidoVenda('${p.id}')">BAIXAR/VENDER</button> <button class="red" onclick="cancelarPedido('${p.id}',${Number(p.total||0)},'${p.data_entrega||''}','${p.hora_entrega||''}')">CANCELAR</button> <button class="red" onclick="del('pedidos','${p.id}');pedidos()">EXCLUIR</button></td></tr>`).join('')}</tbody></table></div>`}
async function pedidos(){const d=await api('/api/pedidos?busca='+encodeURIComponent($('busca')?.value||'')); $('content').innerHTML=`<div class="panel"><h2>PEDIDOS / AGENDAMENTOS</h2><p>Pedido com vários itens, data/hora de entrega ou busca, forma de pagamento e baixa manual da venda.</p><div class="actions"><input id="busca" placeholder="PESQUISAR ACIMA DE 2 LETRAS" oninput="if(this.value.length>1||!this.value) pedidos()" value="${esc($('busca')?.value||'')}"><button onclick="formPedido()">+ NOVO PEDIDO</button></div>${pedidosTabela(d)}</div>`}
async function formPedido(id=null){
  const [clientes,produtos,receitas,formas,pedidosList,itensAll]=await Promise.all([api('/api/clientes'),api('/api/produtos'),api('/api/receitas'),getFormasAvancadas(),api('/api/pedidos'),api('/api/pedido_itens')]);
  window.formasPagamentoAtual=formas; window.pedidoProdutos=[...produtos.map(p=>({...p,kind:'PRODUTO'})),...receitas.map(r=>({id:'R_'+r.id,nome:r.nome,preco_venda:r.preco_venda||0,kind:'RECEITA'}))];
  const ped=id?(pedidosList||[]).find(p=>p.id===id):{}; pedidoCart=id?(itensAll||[]).filter(i=>i.pedido_id===id).map(i=>({...i,total:parseMoney(i.total)})):[]; window.pedidoEditId=id;
  abrirModal(`<h2>${id?'EDITAR':'NOVO'} PEDIDO / AGENDAMENTO</h2><div class="formgrid"><label>CLIENTE<select id="pCliente" onchange="preencherClientePedido()"><option value="">DIGITAR MANUAL</option>${clientes.map(c=>`<option value="${c.id}" ${ped?.cliente_id===c.id?'selected':''}>${esc(c.nome)} - ${esc(c.telefone||c.whatsapp||'')}</option>`).join('')}</select></label><label>NOME CLIENTE<input id="pClienteNome" class="upper" value="${esc(ped?.cliente_nome||'')}"></label><label>TELEFONE<input id="pTelefone" value="${esc(ped?.telefone||'')}"></label><label>DATA ENTREGA/BUSCA<input id="pData" type="date" value="${esc(ped?.data_entrega||'')}"></label><label>HORA<input id="pHora" type="time" value="${esc(ped?.hora_entrega||'')}"></label><label>TIPO<select id="pEntregaTipo"><option ${ped?.entrega_tipo!=='BUSCA'?'selected':''}>ENTREGA</option><option ${ped?.entrega_tipo==='BUSCA'?'selected':''}>BUSCA</option></select></label><label class="full">ENDEREÇO ENTREGA<input id="pEndereco" class="upper" value="${esc(ped?.endereco_entrega||'')}"></label><label>FORMA PAGAMENTO<select id="pForma" onchange="aplicarFormaPagamento('p')">${formas.map(f=>`<option ${formaNome(f)===(ped?.forma_pagamento||'DINHEIRO')?'selected':''}>${formaNome(f)}</option>`).join('')}</select></label><label>STATUS<select id="pStatus"><option ${ped?.status==='AGENDADO'?'selected':''}>AGENDADO</option><option ${ped?.status==='EM PRODUÇÃO'?'selected':''}>EM PRODUÇÃO</option><option ${ped?.status==='PRONTO'?'selected':''}>PRONTO</option><option ${ped?.status==='ENTREGUE'?'selected':''}>ENTREGUE</option><option ${ped?.status==='BAIXADO/VENDIDO'?'selected':''}>BAIXADO/VENDIDO</option></select></label><label>% MULTA CANCELAMENTO<input id="pMultaPerc" type="number" value="${ped?.multa_percentual||0}"></label><label>PRAZO CANCELAMENTO HORAS<input id="pPrazoCancel" type="number" value="${ped?.prazo_cancelamento_horas||24}"></label><label class="full">OBSERVAÇÕES<textarea id="pObs" class="upper">${esc(ped?.observacoes||'')}</textarea></label></div><h3>ITENS DO PEDIDO</h3><div class="formgrid"><label>PRODUTO/RECEITA<select id="pItem">${window.pedidoProdutos.map(p=>`<option value="${p.id}" data-kind="${p.kind}" data-nome="${esc(p.nome)}" data-preco="${p.preco_venda||0}">${esc(p.kind)} - ${esc(p.nome)} - ${money(p.preco_venda||0)}</option>`).join('')}</select></label><label>QUANTIDADE<input id="pQtd" type="number" step="0.001" value="1"></label><label>VALOR UNITÁRIO<input id="pValor" type="number" step="0.01" value="0"></label></div><button class="green" onclick="addItemPedido();aplicarFormaPagamento('p')">ADICIONAR ITEM</button><div id="pedidoCart"></div><h3>PAGAMENTO</h3><div class="formgrid"><label>DESCONTO AUTOMÁTICO<input id="pDescAuto" type="number" readonly value="0"></label><label>JUROS AUTOMÁTICO<input id="pJurosAuto" type="number" readonly value="0"></label><label>DESCONTO MANUAL<input id="pDescManual" type="number" value="${ped?.desconto_manual||0}" oninput="renderPedidoCart()"></label><label>JUROS MANUAL<input id="pJurosManual" type="number" value="0" oninput="renderPedidoCart()"></label></div><div class="kpi" id="pedidoTotal">R$ 0,00</div><button onclick="salvarPedidoCompleto()">SALVAR PEDIDO</button> <button class="secondary" onclick="fecharModal()">FECHAR</button>`);
  $('pItem').onchange=()=>{const o=$('pItem').selectedOptions[0]; $('pValor').value=Number(o.dataset.preco||0).toFixed(2)}; $('pItem').onchange(); renderPedidoCart(); aplicarFormaPagamento('p');
}
function preencherClientePedido(){const c=$('pCliente').selectedOptions[0]; if(!c||!c.value)return; const txt=c.textContent.split(' - '); $('pClienteNome').value=txt[0]||''; $('pTelefone').value=txt[1]||''}
function addItemPedido(){const o=$('pItem').selectedOptions[0], q=parseMoney($('pQtd').value), v=parseMoney($('pValor').value), isRec=o.dataset.kind==='RECEITA'; pedidoCart.push({produto_id:isRec?null:o.value,receita_id:isRec?o.value.replace('R_',''):null,descricao:o.dataset.nome,quantidade:q,valor_unitario:v,total:q*v}); renderPedidoCart()}
function renderPedidoCart(){const subtotal=pedidoCart.reduce((s,i)=>s+parseMoney(i.total),0), t=totalComPagamentos('p',subtotal); if($('pedidoCart'))$('pedidoCart').innerHTML=`${simple(pedidoCart,['descricao','quantidade','valor_unitario','total'])}<p>SUBTOTAL: <b>${money(subtotal)}</b> | DESCONTO: <b>${money(t.desconto)}</b> | JUROS: <b>${money(t.juros)}</b></p>`; if($('pedidoTotal'))$('pedidoTotal').textContent=money(t.total)}
async function salvarPedidoCompleto(){const subtotal=pedidoCart.reduce((s,i)=>s+parseMoney(i.total),0), t=totalComPagamentos('p',subtotal); const body={id:window.pedidoEditId||undefined,cliente_id:$('pCliente').value||null,cliente_nome:$('pClienteNome').value,telefone:$('pTelefone').value,data_entrega:$('pData').value,hora_entrega:$('pHora').value,entrega_tipo:$('pEntregaTipo').value,endereco_entrega:$('pEndereco').value,status:$('pStatus').value,subtotal,desconto:t.desconto,juros:t.juros,total:t.total,forma_pagamento:$('pForma').value,multa_percentual:parseMoney($('pMultaPerc').value),prazo_cancelamento_horas:parseMoney($('pPrazoCancel').value),observacoes:$('pObs').value,itens:pedidoCart}; await api('/api/pedidos/salvar-completo',{method:'POST',body:JSON.stringify(body)}); alert('PEDIDO SALVO'); fecharModal(); pedidos()}
async function cancelarPedido(id,total,data,hora){let perc=parseMoney(prompt('PORCENTAGEM DE MULTA PARA CANCELAMENTO:', '0')); let multa=total*perc/100; const motivo=prompt(`MOTIVO DO CANCELAMENTO. MULTA: ${money(multa)}`,'CANCELAMENTO DE PEDIDO'); if(!motivo)return; await api('/api/pedidos/cancelar/'+id,{method:'POST',body:JSON.stringify({motivo,multa_cancelamento:multa})}); alert('PEDIDO CANCELADO'); pedidos()}
async function baixarPedidoVenda(id){const formas=await getFormasAvancadas(); abrirModal(`<h2>BAIXAR PEDIDO COMO VENDA</h2><label>FORMA DE PAGAMENTO<select id="bxForma">${formas.map(f=>`<option>${formaNome(f)}</option>`).join('')}</select></label><label>STATUS<select id="bxStatus"><option>PAGO</option><option>ABERTO</option></select></label><label><input id="bxEstoque" type="checkbox" checked> BAIXAR ESTOQUE AGORA</label><button class="green" onclick="confirmarBaixaPedido('${id}')">CONFIRMAR BAIXA/VENDA</button>`)}
async function confirmarBaixaPedido(id){await api('/api/pedidos/baixar-venda/'+id,{method:'POST',body:JSON.stringify({forma_pagamento:$('bxForma').value,status:$('bxStatus').value,baixar_estoque:$('bxEstoque').checked})}); alert('PEDIDO BAIXADO COMO VENDA'); fecharModal(); pedidos()}


