function safeMoney(n){return Number(n||0).toLocaleString('pt-BR',{style:'currency',currency:'BRL'})}
function esc2(v){return String(v??'').replace(/[&<>"']/g,s=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[s]))}
