// ===== V5.4 - CORREÇÕES: RECEITAS AÇÕES, PEDIDOS SALVAR/FINALIZAR, PRODUTOS XML/PDF =====
function safeMoney(v){return Number(v||0).toLocaleString('pt-BR',{style:'currency',currency:'BRL'})}
function safeHtml(v){return String(v??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}
function btns(arr){return `<div class="row-actions">${arr.map(a=>`<button class="${a.cls||'secondary'}" onclick="${a.fn}">${a.txt}</button>`).join('')}</div>`}

async function receitas(){
  const busca=$('busca')?.value||'';
  const rows=await api('/api/receitas?busca='+encodeURIComponent(busca));
  $('content').innerHTML=`<div class="panel"><div class="actions"><input id="busca" placeholder="PESQUISAR RECEITA" oninput="if(this.value.length>1||!this.value) receitas()" value="${safeHtml(busca)}"><button onclick="novaReceita()">+ NOVA RECEITA</button></div><div class="card-list">${(rows||[]).map(r=>`<div class="item-card receita-card"><div><div class="item-title">${safeHtml(r.nome)}</div><div class="item-sub">${safeHtml(r.categoria||'')} • ${safeHtml(r.rendimento||'')}</div></div><div class="mini">BASE<br><b>${safeHtml(r.peso_base||1)} ${safeHtml(r.unidade_base||'UN')}</b></div><div class="mini">CUSTO<br><b>${safeMoney(r.custo_total)}</b></div><div class="mini">VENDA<br><b>${safeMoney(r.preco_venda)}</b></div><div class="mini">MARGEM<br><b>${safeHtml(r.margem_percentual||0)}%</b></div>${btns([{txt:'Editar',cls:'secondary',fn:`editarReceita('${r.id}')`},{txt:'Produtos',cls:'',fn:`abrirProdutosReceita('${r.id}')`},{txt:'Imprimir',cls:'green',fn:`imprimirReceita('${r.id}',false)`},{txt:'Excluir',cls:'red',fn:`del('receitas','${r.id}');receitas()`}])}</div>`).join('')||'<p class="muted">Nenhuma receita encontrada.</p>'}</div></div>`;
}
async function novaReceita(){editarReceita(null)}
async function editarReceita(id){
  const recs=id?await api('/api/receitas'):[]; const r=id?recs.find(x=>x.id===id):{};
  abrirModal(`<h2>${id?'EDITAR':'NOVA'} RECEITA</h2><div class="formgrid"><label>NOME<input id="rxNome" class="upper" value="${safeHtml(r?.nome||'')}"></label><label>CATEGORIA<input id="rxCat" class="upper" value="${safeHtml(r?.categoria||'')}"></label><label>BASE<input id="rxBase" type="number" step="0.001" value="${safeHtml(r?.peso_base||1)}"></label><label>UNIDADE<input id="rxUn" class="upper" value="${safeHtml(r?.unidade_base||'UN')}"></label><label>RENDIMENTO<input id="rxRend" class="upper" value="${safeHtml(r?.rendimento||'')}"></label><label>PREÇO VENDA<input id="rxVenda" type="number" step="0.01" value="${safeHtml(r?.preco_venda||0)}"></label><label>MARGEM %<input id="rxMargem" type="number" step="0.01" value="${safeHtml(r?.margem_percentual||0)}"></label><label class="full">MODO DE PREPARO<textarea id="rxPreparo" class="upper">${safeHtml(r?.modo_preparo||'')}</textarea></label></div><button onclick="salvarReceita('${id||''}')">SALVAR</button>`)
}
async function salvarReceita(id){
  const body={nome:$('rxNome').value,categoria:$('rxCat').value,peso_base:$('rxBase').value,unidade_base:$('rxUn').value,rendimento:$('rxRend').value,preco_venda:$('rxVenda').value,margem_percentual:$('rxMargem').value,modo_preparo:$('rxPreparo').value}; if(id) body.id=id;
  await api('/api/receitas',{method:'POST',body:JSON.stringify(body)}); fecharModal(); receitas();
}
async function abrirProdutosReceita(id){
  const [recs,itens,prods]=await Promise.all([api('/api/receitas'),api('/api/receita_itens'),api('/api/produtos')]);
  const r=recs.find(x=>x.id===id); const lista=(itens||[]).filter(i=>i.receita_id===id);
  window.receitaProdId=id; window.receitaProds=prods;
  abrirModal(`<h2>PRODUTOS DA RECEITA</h2><h3>${safeHtml(r?.nome||'')}</h3><div class="formgrid"><label>PRODUTO<select id="riProduto" onchange="preencherProdutoReceita()">${prods.map(p=>`<option value="${p.id}">${safeHtml(p.nome)} - ${safeHtml(p.unidade||'UN')} - ${safeMoney(p.custo_medio||p.custo_unitario)}</option>`).join('')}</select></label><label>QUANTIDADE<input id="riQtd" type="number" step="0.001" value="1"></label><label>UNIDADE<input id="riUn" class="upper" value="UN"></label><label>CUSTO UNITÁRIO<input id="riCusto" type="number" step="0.0001" value="0"></label></div><button class="green" onclick="salvarProdutoReceita()">ADICIONAR PRODUTO</button><hr>${wrapTable(`<table><thead><tr><th>PRODUTO</th><th>QTD</th><th>UN</th><th>CUSTO UNIT.</th><th>TOTAL</th><th>AÇÃO</th></tr></thead><tbody>${lista.map(i=>{const p=prods.find(x=>x.id===i.produto_id); const c=Number(i.custo_unitario||p?.custo_medio||p?.custo_unitario||0), q=Number(i.quantidade||0); return `<tr><td>${safeHtml(p?.nome||i.descricao)}</td><td>${q}</td><td>${safeHtml(i.unidade||p?.unidade||'')}</td><td>${safeMoney(c)}</td><td>${safeMoney(q*c)}</td><td><button class="red" onclick="excluirItemReceita('${i.id}')">EXCLUIR</button></td></tr>`}).join('')}</tbody></table>`) }<div class="actions"><button onclick="imprimirReceita('${id}',false)">IMPRIMIR SEM VALOR</button><button onclick="imprimirReceita('${id}',true)">IMPRIMIR COM VALOR</button></div>`);
  preencherProdutoReceita();
}
function preencherProdutoReceita(){const p=(window.receitaProds||[]).find(x=>x.id===$('riProduto')?.value); if(!p)return; $('riUn').value=p.unidade||'UN'; $('riCusto').value=Number(p.custo_medio||p.custo_unitario||0).toFixed(4)}
async function salvarProdutoReceita(){const p=(window.receitaProds||[]).find(x=>x.id===$('riProduto').value); const body={receita_id:window.receitaProdId,produto_id:p.id,descricao:p.nome,quantidade:$('riQtd').value,unidade:$('riUn').value,custo_unitario:$('riCusto').value}; await api('/api/receita_itens',{method:'POST',body:JSON.stringify(body)}); await recalcularCustoReceita(window.receitaProdId); abrirProdutosReceita(window.receitaProdId)}
async function excluirItemReceita(id){if(!confirm('EXCLUIR PRODUTO DA RECEITA?'))return; await api('/api/receita_itens/'+id,{method:'DELETE'}); await recalcularCustoReceita(window.receitaProdId); abrirProdutosReceita(window.receitaProdId)}
async function recalcularCustoReceita(id){const itens=(await api('/api/receita_itens')).filter(i=>i.receita_id===id); const total=itens.reduce((s,i)=>s+Number(i.quantidade||0)*Number(i.custo_unitario||0),0); await api('/api/receitas',{method:'POST',body:JSON.stringify({id,custo_total:total})})}
async function imprimirReceita(id,comValor){
  const [recs,itens,prods]=await Promise.all([api('/api/receitas'),api('/api/receita_itens'),api('/api/produtos')]); const r=recs.find(x=>x.id===id); const lista=itens.filter(i=>i.receita_id===id);
  const rows=lista.map(i=>{const p=prods.find(x=>x.id===i.produto_id); const c=Number(i.custo_unitario||p?.custo_medio||p?.custo_unitario||0), q=Number(i.quantidade||0); return `<tr><td>${safeHtml(p?.nome||i.descricao)}</td><td>${q}</td><td>${safeHtml(i.unidade||p?.unidade||'')}</td>${comValor?`<td>${safeMoney(c)}</td><td>${safeMoney(q*c)}</td>`:''}</tr>`}).join('');
  const html=`<html><head><title>Receita</title><style>body{font-family:Arial;padding:24px}table{width:100%;border-collapse:collapse}td,th{border:1px solid #ccc;padding:8px;text-align:left}h1{text-align:center}</style></head><body><h1>RECEITA - ${safeHtml(r?.nome||'')}</h1><p><b>Categoria:</b> ${safeHtml(r?.categoria||'')} &nbsp; <b>Base:</b> ${safeHtml(r?.peso_base||1)} ${safeHtml(r?.unidade_base||'')} &nbsp; <b>Rendimento:</b> ${safeHtml(r?.rendimento||'')}</p>${comValor?`<p><b>Custo:</b> ${safeMoney(r?.custo_total)} &nbsp; <b>Venda:</b> ${safeMoney(r?.preco_venda)}</p>`:''}<table><thead><tr><th>Produto</th><th>Quantidade</th><th>Unidade</th>${comValor?'<th>Custo unit.</th><th>Total</th>':''}</tr></thead><tbody>${rows}</tbody></table><h3>Modo de preparo</h3><p>${safeHtml(r?.modo_preparo||'')}</p></body></html>`;
  const w=open('','_blank'); w.document.write(html); w.document.close(); w.print();
}

async function pedidos(){
  const busca=$('buscaPedidos')?.value||'';
  const d=await api('/api/pedidos?busca='+encodeURIComponent(busca));
  $('content').innerHTML=`<div class="panel"><div class="actions"><input id="buscaPedidos" placeholder="BUSCAR POR CLIENTE / NÚMERO / DATA" value="${safeHtml(busca)}" oninput="if(this.value.length>1||!this.value) pedidos()"><button onclick="formPedido()">+ NOVO PEDIDO</button></div>${pedidosTabelaV54(d)}</div>`;
}
function pedidosTabelaV54(rows){return wrapTable(`<table><thead><tr><th>CLIENTE</th><th>DATA</th><th>HORA</th><th>TIPO</th><th>TOTAL</th><th>FORMA</th><th>STATUS</th><th>AÇÕES</th></tr></thead><tbody>${(rows||[]).map(p=>`<tr><td>${safeHtml(p.cliente_nome)}</td><td>${safeHtml(p.data_entrega||'')}</td><td>${safeHtml(p.hora_entrega||'')}</td><td>${safeHtml(p.entrega_tipo||'ENTREGA')}</td><td>${safeMoney(p.total)}</td><td>${safeHtml(p.forma_pagamento||'')}</td><td>${safeHtml(p.status||'')}</td><td>${(p.status==='BAIXADO/VENDIDO')?'<b>SOMENTE CONSULTA</b>':btns([{txt:'Editar',cls:'secondary',fn:`formPedido('${p.id}')`},{txt:'Finalizar',cls:'green',fn:`baixarPedidoVenda('${p.id}')`},{txt:'Cancelar',cls:'red',fn:`cancelarPedido('${p.id}',${Number(p.total||0)},'${p.data_entrega||''}','${p.hora_entrega||''}')`},{txt:'Excluir',cls:'red',fn:`del('pedidos','${p.id}');pedidos()`}])}</td></tr>`).join('')}</tbody></table>`)}
async function formPedido(id){
  const [clientes,produtos,receitas,formas,pedidosList,itensAll]=await Promise.all([api('/api/clientes'),api('/api/produtos'),api('/api/receitas'),getFormasAvancadas(),api('/api/pedidos'),api('/api/pedido_itens')]);
  window.formasPagamentoAtual=formas; window.pedidoProdutos=[...produtos.map(p=>({...p,kind:'PRODUTO'})),...receitas.map(r=>({id:'R_'+r.id,nome:r.nome,preco_venda:r.preco_venda||0,kind:'RECEITA'}))];
  const ped=id?(pedidosList||[]).find(p=>p.id===id):{}; if(ped?.status==='BAIXADO/VENDIDO') return alert('PEDIDO FINALIZADO FICA SOMENTE PARA CONSULTA.'); pedidoCart=id?(itensAll||[]).filter(i=>i.pedido_id===id).map(i=>({...i,total:Number(i.total||0)})):[]; window.pedidoEditId=id||null;
  abrirModal(`<h2>${id?'EDITAR':'NOVO'} PEDIDO / AGENDAMENTO</h2><div class="formgrid"><label>CLIENTE<select id="pCliente" onchange="preencherClientePedido()"><option value="">DIGITAR MANUAL</option>${clientes.map(c=>`<option value="${c.id}" ${ped?.cliente_id===c.id?'selected':''}>${safeHtml(c.nome)} - ${safeHtml(c.telefone||c.whatsapp||'')}</option>`).join('')}</select></label><label>NOME CLIENTE<input id="pClienteNome" class="upper" value="${safeHtml(ped?.cliente_nome||'')}"></label><label>TELEFONE<input id="pTelefone" value="${safeHtml(ped?.telefone||'')}"></label><label>DATA ENTREGA/BUSCA<input id="pData" type="date" value="${safeHtml(ped?.data_entrega||'')}"></label><label>HORA<input id="pHora" type="time" value="${safeHtml(ped?.hora_entrega||'')}"></label><label>TIPO<select id="pEntregaTipo"><option ${ped?.entrega_tipo!=='BUSCA'?'selected':''}>ENTREGA</option><option ${ped?.entrega_tipo==='BUSCA'?'selected':''}>BUSCA</option></select></label><label class="full">ENDEREÇO ENTREGA<input id="pEndereco" class="upper" value="${safeHtml(ped?.endereco_entrega||'')}"></label><label>FORMA PAGAMENTO<select id="pForma" onchange="aplicarFormaPagamento('p')">${formas.map(f=>`<option ${formaNome(f)===(ped?.forma_pagamento||'DINHEIRO')?'selected':''}>${safeHtml(formaNome(f))}</option>`).join('')}</select></label><label>STATUS<select id="pStatus"><option ${ped?.status==='AGENDADO'?'selected':''}>AGENDADO</option><option ${ped?.status==='EM PRODUÇÃO'?'selected':''}>EM PRODUÇÃO</option><option ${ped?.status==='PRONTO'?'selected':''}>PRONTO</option><option ${ped?.status==='ENTREGUE'?'selected':''}>ENTREGUE</option></select></label><label>% MULTA CANCELAMENTO<input id="pMultaPerc" type="number" value="${ped?.multa_percentual||0}"></label><label>PRAZO CANCELAMENTO HORAS<input id="pPrazoCancel" type="number" value="${ped?.prazo_cancelamento_horas||24}"></label><label class="full">OBSERVAÇÕES<textarea id="pObs" class="upper">${safeHtml(ped?.observacoes||'')}</textarea></label></div><h3>ITENS DO PEDIDO</h3><div class="formgrid"><label>PRODUTO/RECEITA<select id="pItem" onchange="atualizaPrecoPedido()">${window.pedidoProdutos.map(p=>`<option value="${p.id}" data-kind="${p.kind}" data-nome="${safeHtml(p.nome)}" data-preco="${p.preco_venda||0}">${safeHtml(p.kind)} - ${safeHtml(p.nome)} - ${safeMoney(p.preco_venda||0)}</option>`).join('')}</select></label><label>QUANTIDADE<input id="pQtd" type="number" step="0.001" value="1"></label><label>VALOR UNITÁRIO<input id="pValor" type="number" step="0.01" value="0"></label></div><button class="green" onclick="addItemPedido();aplicarFormaPagamento('p')">ADICIONAR ITEM</button><div id="pedidoCart"></div><h3>PAGAMENTO</h3><div class="formgrid"><label>DESCONTO AUTOMÁTICO<input id="pDescAuto" type="number" readonly value="0"></label><label>JUROS AUTOMÁTICO<input id="pJurosAuto" type="number" readonly value="0"></label><label>DESCONTO MANUAL<input id="pDescManual" type="number" value="0" oninput="renderPedidoCart()"></label><label>JUROS MANUAL<input id="pJurosManual" type="number" value="0" oninput="renderPedidoCart()"></label></div><div class="kpi" id="pedidoTotal">R$ 0,00</div><button onclick="salvarPedidoCompleto()">SALVAR PEDIDO</button><button class="secondary" onclick="fecharModal()">FECHAR</button>`);
  atualizaPrecoPedido(); renderPedidoCart(); aplicarFormaPagamento('p');
}
function atualizaPrecoPedido(){const o=$('pItem')?.selectedOptions?.[0]; if(o&&$('pValor')) $('pValor').value=Number(o.dataset.preco||0).toFixed(2)}
async function salvarPedidoCompleto(){
  try{ if(!pedidoCart.length) return alert('ADICIONE AO MENOS 1 ITEM NO PEDIDO.'); const subtotal=pedidoCart.reduce((s,i)=>s+Number(i.total||0),0), t=totalComPagamentos('p',subtotal); const body={id:window.pedidoEditId||undefined,cliente_id:$('pCliente').value||null,cliente_nome:$('pClienteNome').value||'CONSUMIDOR',telefone:$('pTelefone').value,data_entrega:$('pData').value||null,hora_entrega:$('pHora').value,entrega_tipo:$('pEntregaTipo').value,endereco_entrega:$('pEndereco').value,status:$('pStatus').value,subtotal,desconto:t.desconto,juros:t.juros,total:t.total,forma_pagamento:$('pForma').value,multa_percentual:Number($('pMultaPerc').value||0),prazo_cancelamento_horas:Number($('pPrazoCancel').value||24),observacoes:$('pObs').value,itens:pedidoCart}; await api('/api/pedidos/salvar-completo',{method:'POST',body:JSON.stringify(body)}); alert('PEDIDO SALVO COM SUCESSO'); fecharModal(); pedidos(); }catch(e){alert('ERRO AO SALVAR PEDIDO: '+e.message)}
}
async function baixarPedidoVenda(id){const formas=await getFormasAvancadas(); abrirModal(`<h2>FINALIZAR PEDIDO</h2><p>Ao finalizar, o pedido vira venda, muda o status e pode baixar o estoque.</p><label>FORMA DE PAGAMENTO<select id="bxForma">${formas.map(f=>`<option>${safeHtml(formaNome(f))}</option>`).join('')}</select></label><label>STATUS VENDA<select id="bxStatus"><option>PAGO</option><option>ABERTO</option></select></label><label><input id="bxEstoque" type="checkbox" checked> BAIXAR ESTOQUE</label><button class="green" onclick="confirmarBaixaPedido('${id}')">CONFIRMAR FINALIZAÇÃO</button>`)}
async function confirmarBaixaPedido(id){try{await api('/api/pedidos/baixar-venda/'+id,{method:'POST',body:JSON.stringify({forma_pagamento:$('bxForma').value,status:$('bxStatus').value,baixar_estoque:$('bxEstoque').checked})}); alert('PEDIDO FINALIZADO E BAIXADO COMO VENDA'); fecharModal(); pedidos()}catch(e){alert('ERRO AO FINALIZAR: '+e.message)}}

async function produtos(){
  const busca=$('busca')?.value||''; const rows=await api('/api/produtos?busca='+encodeURIComponent(busca)); const cols=produtoCols();
  $('content').innerHTML=`<div class="panel"><div class="actions"><input id="busca" placeholder="PESQUISAR PRODUTO" oninput="if(this.value.length>1||!this.value) produtos()" value="${safeHtml(busca)}"><button onclick='formCrud("produtos","NOVO PRODUTO",${JSON.stringify(cols)})'>+ NOVO PRODUTO</button><button class="green" onclick="abrirImportarXML()">IMPORTAR XML</button><button class="green" onclick="abrirImportarPDF()">IMPORTAR PDF NF</button></div><div class="card-list">${(rows||[]).map(p=>`<div class="item-card"><div><div class="item-title">${safeHtml(p.nome)}</div><div class="item-sub">${safeHtml(p.tipo||'')} • ${safeHtml(p.categoria||'')} • ${safeHtml(p.unidade||'UN')}</div></div><div class="mini">CUSTO<br><b>${safeMoney(p.custo_unitario||p.custo_medio)}</b></div><div class="mini">VENDA<br><b>${safeMoney(p.preco_venda)}</b></div><div class="mini">ESTOQUE<br><b>${safeHtml(p.estoque_atual||0)} ${safeHtml(p.unidade||'')}</b></div><div class="mini">MÍNIMO<br><b>${safeHtml(p.estoque_minimo||0)}</b></div>${btns([{txt:'Editar',cls:'secondary',fn:`formCrud('produtos','EDITAR PRODUTO',${JSON.stringify(cols)},${JSON.stringify(p).replace(/'/g,'&#39;')})`},{txt:'Excluir',cls:'red',fn:`excluirProduto('${p.id}')`}])}</div>`).join('')||'<p class="muted">Nenhum produto encontrado.</p>'}</div></div>`;
}
async function abrirImportarPDF(){abrirModal(`<h2>IMPORTAR PDF / DANFE</h2><p>Importa os produtos da nota por PDF. Exemplo compatível: DANFE/NF-e como o arquivo enviado.</p><input id="pdfFile" type="file" accept=".pdf,application/pdf"><button class="green" onclick="analisarPDFNF()">ANALISAR PDF</button><div id="pdfResultado"></div>`)}
async function analisarPDFNF(){const f=$('pdfFile').files[0]; if(!f)return alert('SELECIONE O PDF'); const fd=new FormData(); fd.append('pdf',f); const r=await fetch('/api/compras/importar-pdf-analisar',{method:'POST',body:fd}).then(r=>r.json()); if(!r.ok)return alert(r.error); window.xmlAnalise=r.data; await renderAnaliseNF('pdfResultado',r.data)}
async function renderAnaliseNF(targetId,data){const prods=await api('/api/produtos'); const forn=await api('/api/fornecedores'); $(targetId).innerHTML=`<h3>FORNECEDOR</h3><p>${safeHtml(data.fornecedor.nome)} - ${safeHtml(data.fornecedor.cnpj)}</p><label>VINCULAR FORNECEDOR<select id="xmlFornecedor"><option value="">CRIAR / USAR DO ARQUIVO</option>${forn.map(f=>`<option value="${f.id}" ${data.fornecedor.sugestao_id===f.id?'selected':''}>${safeHtml(f.nome)} - ${safeHtml(f.cnpj||'')}</option>`).join('')}</select></label><h3>PRODUTOS DA NOTA</h3>${wrapTable(`<table><thead><tr><th>ARQUIVO</th><th>QTD</th><th>VALOR UNIT.</th><th>VINCULAR PRODUTO</th></tr></thead><tbody>${data.itens.map((it,i)=>`<tr><td>${safeHtml(it.nome)}<br><small>${safeHtml(it.codigo||'')}</small></td><td>${it.quantidade} ${safeHtml(it.unidade)}</td><td>${safeMoney(it.valor_unitario)}</td><td><select id="xmlProd_${i}"><option value="">CRIAR / USAR DO ARQUIVO</option>${prods.map(p=>`<option value="${p.id}" ${it.sugestao_id===p.id?'selected':''}>${safeHtml(p.nome)}</option>`).join('')}</select></td></tr>`).join('')}</tbody></table>`)}<button class="green" onclick="confirmarImportarXML()">IMPORTAR COMPRA / ENTRAR ESTOQUE</button>`}
// Ajusta o analisador XML para usar a mesma tela reforçada.
async function analisarXML(){const f=$('xmlFile').files[0]; if(!f)return alert('SELECIONE O XML'); const fd=new FormData(); fd.append('xml',f); const r=await fetch('/api/compras/importar-xml-analisar',{method:'POST',body:fd}).then(r=>r.json()); if(!r.ok)return alert(r.error); window.xmlAnalise=r.data; await renderAnaliseNF('xmlResultado',r.data)}

// ===== V5.5 - REFORÇO GERAL CRUD RECEITAS / PEDIDOS / PRODUTOS =====
function v55Esc(v){return String(v??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}
function v55Money(v){return Number(v||0).toLocaleString('pt-BR',{style:'currency',currency:'BRL'})}
function v55Num(v){return Number(String(v??0).replace(',','.'))||0}
function v55Btns(arr){return `<div class="row-actions">${arr.map(a=>`<button class="${a.cls||'secondary'}" onclick="${a.fn}">${a.txt}</button>`).join('')}</div>`}
function v55ProdutoNome(p){return `${v55Esc(p.nome)} - ${v55Esc(p.unidade||'UN')} - ${v55Money(p.custo_medio||p.custo_unitario||0)}`}

async function receitas(){
  try{
    const busca=$('buscaReceitas')?.value||'';
    const rows=await api('/api/receitas?busca='+encodeURIComponent(busca));
    $('content').innerHTML=`<div class="panel"><div class="actions"><input id="buscaReceitas" placeholder="PESQUISAR RECEITA" value="${v55Esc(busca)}" oninput="if(this.value.length>1||!this.value) receitas()"><button onclick="editarReceitaV55()">+ NOVA RECEITA</button></div><div class="card-list">${(rows||[]).map(r=>`<div class="item-card receita-card"><div><div class="item-title">${v55Esc(r.nome)}</div><div class="item-sub">${v55Esc(r.categoria||'')} • ${v55Esc(r.rendimento||'')}</div></div><div class="mini">BASE<br><b>${v55Esc(r.peso_base||1)} ${v55Esc(r.unidade_base||'UN')}</b></div><div class="mini">CUSTO<br><b>${canVerValoresReceita()?v55Money(r.custo_total):'***'}</b></div><div class="mini">VENDA<br><b>${canVerValoresReceita()?v55Money(r.preco_venda):'***'}</b></div><div class="mini">MARGEM<br><b>${v55Esc(r.margem_percentual||0)}%</b></div>${v55Btns([{txt:'Editar',fn:`editarReceitaV55('${r.id}')`},{txt:'Produtos',fn:`abrirProdutosReceitaV55('${r.id}')`},{txt:'Imprimir sem valor',cls:'green',fn:`imprimirReceitaV55('${r.id}',false)`},...(canVerValoresReceita()?[{txt:'Imprimir com valor',fn:`imprimirReceitaV55('${r.id}',true)`}]:[]),{txt:'Excluir',cls:'red',fn:`excluirRegistroV55('receitas','${r.id}',receitas)`}])}</div>`).join('')||'<p class="muted">Nenhuma receita encontrada.</p>'}</div></div>`;
  }catch(e){alert('ERRO AO ABRIR RECEITAS: '+e.message)}
}
async function editarReceitaV55(id=''){
  const recs=id?await api('/api/receitas'):[]; const r=id?(recs||[]).find(x=>x.id===id)||{}:{};
  abrirModal(`<h2>${id?'EDITAR':'NOVA'} RECEITA</h2><div class="formgrid"><label>NOME<input id="v55RecNome" class="upper" value="${v55Esc(r.nome||'')}"></label><label>CATEGORIA<input id="v55RecCat" class="upper" value="${v55Esc(r.categoria||'')}"></label><label>BASE<input id="v55RecBase" type="number" step="0.001" value="${v55Esc(r.peso_base||1)}"></label><label>UNIDADE<input id="v55RecUn" class="upper" value="${v55Esc(r.unidade_base||'UN')}"></label><label>RENDIMENTO<input id="v55RecRend" class="upper" value="${v55Esc(r.rendimento||'')}"></label><label>PREÇO VENDA<input id="v55RecVenda" type="number" step="0.01" value="${v55Esc(r.preco_venda||0)}"></label><label>MARGEM %<input id="v55RecMargem" type="number" step="0.01" value="${v55Esc(r.margem_percentual||0)}"></label><label class="full">MODO DE PREPARO<textarea id="v55RecPreparo" class="upper">${v55Esc(r.modo_preparo||'')}</textarea></label></div><button onclick="salvarReceitaV55('${id}')">SALVAR</button><button class="secondary" onclick="fecharModal()">FECHAR</button>`);
}
async function salvarReceitaV55(id=''){
  try{
    if(!$('v55RecNome').value.trim()) return alert('INFORME O NOME DA RECEITA.');
    const body={nome:$('v55RecNome').value,categoria:$('v55RecCat').value,peso_base:v55Num($('v55RecBase').value),unidade_base:$('v55RecUn').value,rendimento:$('v55RecRend').value,preco_venda:v55Num($('v55RecVenda').value),margem_percentual:v55Num($('v55RecMargem').value),modo_preparo:$('v55RecPreparo').value};
    if(id) body.id=id;
    const saved=await api('/api/receitas',{method:'POST',body:JSON.stringify(body)});
    fecharModal(); await receitas();
    if(!id && confirm('Receita salva. Deseja adicionar os produtos/ingredientes agora?')) abrirProdutosReceitaV55(saved.id);
  }catch(e){alert('ERRO AO SALVAR RECEITA: '+e.message)}
}
async function abrirProdutosReceitaV55(receitaId){
  try{
    const [recs,prods,itens]=await Promise.all([api('/api/receitas'),api('/api/produtos'),api('/api/receita_itens')]);
    const r=(recs||[]).find(x=>x.id===receitaId)||{}; const lista=(itens||[]).filter(i=>i.receita_id===receitaId);
    window.v55ReceitaId=receitaId; window.v55Produtos=prods||[];
    const total=lista.reduce((s,i)=>s+v55Num(i.quantidade)*v55Num(i.custo_unitario),0);
    abrirModal(`<h2>PRODUTOS DA RECEITA</h2><h3>${v55Esc(r.nome||'')}</h3><p class="muted">Adicione vários produtos do cadastro. Exemplo: 100 GR farinha, 1 L leite.</p><div class="formgrid"><label>PRODUTO<select id="v55RiProduto" onchange="preencherProdutoReceitaV55()"><option value="">SELECIONE</option>${(prods||[]).map(p=>`<option value="${p.id}">${v55ProdutoNome(p)}</option>`).join('')}</select></label><label>QUANTIDADE<input id="v55RiQtd" type="number" step="0.001" value="1"></label><label>UNIDADE<input id="v55RiUn" class="upper" value="UN"></label><label>CUSTO UNITÁRIO<input id="v55RiCusto" type="number" step="0.0001" value="0"></label></div><button class="green" onclick="salvarProdutoReceitaV55()">ADICIONAR PRODUTO</button><hr>${wrapTable(`<table><thead><tr><th>PRODUTO</th><th>QTD</th><th>UN</th>${canVerValoresReceita()?'<th>CUSTO UNIT.</th><th>TOTAL</th>':''}<th>AÇÃO</th></tr></thead><tbody>${lista.map(i=>{const p=(prods||[]).find(x=>x.id===i.produto_id); const q=v55Num(i.quantidade), c=v55Num(i.custo_unitario||p?.custo_medio||p?.custo_unitario); return `<tr><td>${v55Esc(p?.nome||i.descricao||'PRODUTO EXCLUÍDO')}</td><td>${q}</td><td>${v55Esc(i.unidade||p?.unidade||'UN')}</td>${canVerValoresReceita()?`<td>${v55Money(c)}</td><td>${v55Money(q*c)}</td>`:''}<td><button class="red" onclick="excluirProdutoReceitaV55('${i.id}')">EXCLUIR</button></td></tr>`}).join('')}</tbody></table>`) }${canVerValoresReceita()?`<div class="kpi">CUSTO ATUAL: ${v55Money(total)}</div>`:''}<div class="actions"><button class="green" onclick="imprimirReceitaV55('${receitaId}',false)">IMPRIMIR SEM VALOR</button>${canVerValoresReceita()?`<button onclick="imprimirReceitaV55('${receitaId}',true)">IMPRIMIR COM VALOR</button>`:''}<button class="secondary" onclick="fecharModal()">FECHAR</button></div>`);
    preencherProdutoReceitaV55();
  }catch(e){alert('ERRO AO ABRIR PRODUTOS DA RECEITA: '+e.message)}
}
function preencherProdutoReceitaV55(){const p=(window.v55Produtos||[]).find(x=>x.id===$('v55RiProduto')?.value); if(!p)return; $('v55RiUn').value=p.unidade||'UN'; $('v55RiCusto').value=Number(p.custo_medio||p.custo_unitario||0).toFixed(4)}
async function salvarProdutoReceitaV55(){
  try{
    const p=(window.v55Produtos||[]).find(x=>x.id===$('v55RiProduto')?.value);
    if(!p) return alert('SELECIONE UM PRODUTO.');
    const qtd=v55Num($('v55RiQtd').value); if(qtd<=0) return alert('INFORME A QUANTIDADE.');
    const body={receita_id:window.v55ReceitaId,produto_id:p.id,descricao:p.nome,quantidade:qtd,unidade:$('v55RiUn').value||p.unidade||'UN',custo_unitario:v55Num($('v55RiCusto').value||p.custo_medio||p.custo_unitario)};
    await api('/api/receita_itens',{method:'POST',body:JSON.stringify(body)});
    await recalcularCustoReceitaV55(window.v55ReceitaId);
    await abrirProdutosReceitaV55(window.v55ReceitaId);
  }catch(e){alert('ERRO AO ADICIONAR PRODUTO NA RECEITA: '+e.message)}
}
async function excluirProdutoReceitaV55(id){try{if(!confirm('EXCLUIR ESTE PRODUTO DA RECEITA?'))return; await api('/api/receita_itens/'+id,{method:'DELETE'}); await recalcularCustoReceitaV55(window.v55ReceitaId); await abrirProdutosReceitaV55(window.v55ReceitaId);}catch(e){alert('ERRO AO EXCLUIR ITEM: '+e.message)}}
async function recalcularCustoReceitaV55(id){const itens=(await api('/api/receita_itens')).filter(i=>i.receita_id===id); const total=itens.reduce((s,i)=>s+v55Num(i.quantidade)*v55Num(i.custo_unitario),0); await api('/api/receitas',{method:'POST',body:JSON.stringify({id,custo_total:Number(total.toFixed(2))})});}
function opcoesImprimirReceitaV55(id){
  if(!canVerValoresReceita()) return imprimirReceitaV55(id,false);
  abrirModal(`<h2>IMPRIMIR RECEITA</h2><p>Escolha o modelo de impressão:</p><div class="actions"><button class="green" onclick="imprimirReceitaV55('${id}',false)">IMPRIMIR SEM VALOR</button><button onclick="imprimirReceitaV55('${id}',true)">IMPRIMIR COM VALOR</button><button class="secondary" onclick="fecharModal()">FECHAR</button></div>`);
}
async function imprimirReceitaV55(id,comValor=false){const [recs,itens,prods]=await Promise.all([api('/api/receitas'),api('/api/receita_itens'),api('/api/produtos')]); const r=(recs||[]).find(x=>x.id===id)||{}; const lista=(itens||[]).filter(i=>i.receita_id===id); const rows=lista.map(i=>{const p=(prods||[]).find(x=>x.id===i.produto_id); const q=v55Num(i.quantidade), c=v55Num(i.custo_unitario||p?.custo_medio||p?.custo_unitario); return `<tr><td>${v55Esc(p?.nome||i.descricao||'PRODUTO EXCLUÍDO')}</td><td>${q}</td><td>${v55Esc(i.unidade||p?.unidade||'UN')}</td>${comValor?`<td>${v55Money(c)}</td><td>${v55Money(q*c)}</td>`:''}</tr>`}).join(''); const html=`<html><head><title>Receita</title><style>@page{size:A4;margin:14mm}body{font-family:Arial,sans-serif;color:#111;padding:0;margin:0;font-size:13px}.cab{border-bottom:2px solid #111;padding-bottom:10px;margin-bottom:14px;text-align:center}h1{margin:0;font-size:22px}h2{margin:6px 0 0;font-size:17px}.info{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin:10px 0}.box{border:1px solid #999;padding:8px;border-radius:4px}table{width:100%;border-collapse:collapse;margin-top:10px}th{background:#eee}th,td{border:1px solid #999;padding:7px;text-align:left}.preparo{border:1px solid #999;padding:10px;min-height:80px;white-space:pre-wrap}.rodape{margin-top:28px;display:flex;justify-content:space-between}.no-print{margin:10px 0}@media print{.no-print{display:none}}</style></head><body><div class="cab"><h1>FICHA DE RECEITA</h1><h2>${v55Esc(r.nome||'')}</h2></div><div class="info"><div class="box"><b>Categoria:</b><br>${v55Esc(r.categoria||'')}</div><div class="box"><b>Base:</b><br>${v55Esc(r.peso_base||1)} ${v55Esc(r.unidade_base||'UN')}</div><div class="box"><b>Rendimento:</b><br>${v55Esc(r.rendimento||'')}</div></div>${comValor?`<div class="info"><div class="box"><b>Custo:</b><br>${v55Money(r.custo_total)}</div><div class="box"><b>Venda:</b><br>${v55Money(r.preco_venda)}</div><div class="box"><b>Margem:</b><br>${v55Esc(r.margem_percentual||0)}%</div></div>`:''}<h3>Produtos / Ingredientes</h3><table><thead><tr><th>Produto</th><th>Quantidade</th><th>Unidade</th>${comValor?'<th>Custo Unit.</th><th>Total</th>':''}</tr></thead><tbody>${rows}</tbody></table><h3>Modo de preparo</h3><div class="preparo">${v55Esc(r.modo_preparo||'')}</div><div class="rodape"><span>Responsável: __________________________</span><span>Data: ____/____/______</span></div><div class="no-print"><button onclick="window.print()">Imprimir</button></div><script>window.onload=()=>setTimeout(()=>window.print(),300)</script></body></html>`; const w=open('','_blank'); w.document.write(html); w.document.close(); w.print();}

async function excluirRegistroV55(t,id,cb){try{if(!confirm('CONFIRMA EXCLUSÃO?'))return; await api('/api/'+t+'/'+id,{method:'DELETE'}); if(typeof cb==='function') cb();}catch(e){alert('ERRO AO EXCLUIR: '+e.message)}}
async function excluirProduto(id){try{if(!confirm('EXCLUIR PRODUTO?'))return; await api('/api/produtos/'+id,{method:'DELETE'}); produtos();}catch(e){if(String(e.message).includes('RECEITA')){if(confirm(e.message+'\n\nDeseja excluir mesmo assim? A receita ficará incompleta.')){await api('/api/produtos/'+id+'?force=true',{method:'DELETE'}); produtos();}}else alert('ERRO AO EXCLUIR PRODUTO: '+e.message)}}

async function pedidos(){
  try{const busca=$('buscaPedidos')?.value||''; const d=await api('/api/pedidos?busca='+encodeURIComponent(busca)); $('content').innerHTML=`<div class="panel"><div class="actions"><input id="buscaPedidos" placeholder="BUSCAR CLIENTE / NÚMERO / DATA" value="${v55Esc(busca)}" oninput="if(this.value.length>1||!this.value) pedidos()"><button onclick="formPedido()">+ NOVO PEDIDO</button></div>${pedidosTabelaV55(d)}</div>`;}catch(e){alert('ERRO AO ABRIR PEDIDOS: '+e.message)}
}
function pedidosTabelaV55(rows){return wrapTable(`<table><thead><tr><th>CLIENTE</th><th>DATA</th><th>HORA</th><th>TIPO</th><th>TOTAL</th><th>FORMA</th><th>STATUS</th><th>AÇÕES</th></tr></thead><tbody>${(rows||[]).map(p=>{const fechado=['BAIXADO/VENDIDO','CANCELADO','FINALIZADO'].includes(String(p.status||'').toUpperCase()); return `<tr><td>${v55Esc(p.cliente_nome)}</td><td>${v55Esc(p.data_entrega||'')}</td><td>${v55Esc(p.hora_entrega||'')}</td><td>${v55Esc(p.entrega_tipo||'ENTREGA')}</td><td>${v55Money(p.total)}</td><td>${v55Esc(p.forma_pagamento||'')}</td><td>${v55Esc(p.status||'')}</td><td>${fechado?`<button class="secondary" onclick="visualizarPedidoV55('${p.id}')">CONSULTAR</button>`:v55Btns([{txt:'Editar',fn:`formPedido('${p.id}')`},{txt:'Finalizar',cls:'green',fn:`baixarPedidoVenda('${p.id}')`},{txt:'Cancelar',cls:'red',fn:`cancelarPedido('${p.id}',${Number(p.total||0)},'${p.data_entrega||''}','${p.hora_entrega||''}')`},{txt:'Excluir',cls:'red',fn:`excluirRegistroV55('pedidos','${p.id}',pedidos)`}])}</td></tr>`}).join('')}</tbody></table>`)}
async function visualizarPedidoV55(id){const [pedidosAll,itens]=await Promise.all([api('/api/pedidos'),api('/api/pedido_itens')]); const p=(pedidosAll||[]).find(x=>x.id===id)||{}; const its=(itens||[]).filter(i=>i.pedido_id===id); abrirModal(`<h2>CONSULTA DO PEDIDO</h2><p><b>Cliente:</b> ${v55Esc(p.cliente_nome)}<br><b>Status:</b> ${v55Esc(p.status)}<br><b>Entrega:</b> ${v55Esc(p.data_entrega||'')} ${v55Esc(p.hora_entrega||'')} - ${v55Esc(p.entrega_tipo||'')}</p>${wrapTable(`<table><thead><tr><th>Item</th><th>Qtd</th><th>Valor</th><th>Total</th></tr></thead><tbody>${its.map(i=>`<tr><td>${v55Esc(i.descricao)}</td><td>${v55Esc(i.quantidade)}</td><td>${v55Money(i.valor_unitario)}</td><td>${v55Money(i.total)}</td></tr>`).join('')}</tbody></table>`)}<div class="kpi">${v55Money(p.total)}</div><button class="secondary" onclick="fecharModal()">FECHAR</button>`)}

async function formPedido(id=''){
  try{
    const [clientes,produtos,receitas,formas,pedidosList,itensAll]=await Promise.all([api('/api/clientes'),api('/api/produtos'),api('/api/receitas'),getFormasAvancadas(),api('/api/pedidos'),api('/api/pedido_itens')]);
    const ped=id?(pedidosList||[]).find(p=>p.id===id)||{}:{}; if(['BAIXADO/VENDIDO','CANCELADO','FINALIZADO'].includes(String(ped.status||'').toUpperCase())) return visualizarPedidoV55(id);
    window.formasPagamentoAtual=formas; window.pedidoEditId=id||null; window.pedidoProdutos=[...(produtos||[]).map(p=>({...p,kind:'PRODUTO',ref:p.id,preco:p.preco_venda||0})),...(receitas||[]).map(r=>({...r,kind:'RECEITA',ref:r.id,preco:r.preco_venda||0}))]; window.pedidoCart=id?(itensAll||[]).filter(i=>i.pedido_id===id).map(i=>({...i,total:v55Num(i.total)})):[];
    abrirModal(`<h2>${id?'EDITAR':'NOVO'} PEDIDO</h2><div class="formgrid"><label>CLIENTE<select id="pCliente" onchange="preencherClientePedidoV55()"><option value="">DIGITAR MANUAL</option>${(clientes||[]).map(c=>`<option value="${c.id}" ${ped.cliente_id===c.id?'selected':''}>${v55Esc(c.nome)} - ${v55Esc(c.telefone||c.whatsapp||'')}</option>`).join('')}</select></label><label>NOME CLIENTE<input id="pClienteNome" class="upper" value="${v55Esc(ped.cliente_nome||'')}"></label><label>TELEFONE<input id="pTelefone" value="${v55Esc(ped.telefone||'')}"></label><label>DATA ENTREGA/BUSCA<input id="pData" type="date" value="${v55Esc(ped.data_entrega||'')}"></label><label>HORA<input id="pHora" type="time" value="${v55Esc(ped.hora_entrega||'')}"></label><label>TIPO<select id="pEntregaTipo"><option ${ped.entrega_tipo!=='BUSCA'?'selected':''}>ENTREGA</option><option ${ped.entrega_tipo==='BUSCA'?'selected':''}>BUSCA</option></select></label><label class="full">ENDEREÇO<input id="pEndereco" class="upper" value="${v55Esc(ped.endereco_entrega||'')}"></label><label>FORMA PAGAMENTO<select id="pForma" onchange="aplicarFormaPagamento('p')">${formas.map(f=>`<option ${formaNome(f)===(ped.forma_pagamento||'DINHEIRO')?'selected':''}>${v55Esc(formaNome(f))}</option>`).join('')}</select></label><label>STATUS<select id="pStatus"><option ${ped.status==='AGENDADO'?'selected':''}>AGENDADO</option><option ${ped.status==='EM PRODUÇÃO'?'selected':''}>EM PRODUÇÃO</option><option ${ped.status==='PRONTO'?'selected':''}>PRONTO</option><option ${ped.status==='ENTREGUE'?'selected':''}>ENTREGUE</option></select></label><label>% MULTA CANCELAMENTO<input id="pMultaPerc" type="number" value="${ped.multa_percentual||0}"></label><label>PRAZO CANCELAMENTO HORAS<input id="pPrazoCancel" type="number" value="${ped.prazo_cancelamento_horas||24}"></label><label class="full">OBSERVAÇÕES<textarea id="pObs" class="upper">${v55Esc(ped.observacoes||'')}</textarea></label></div><h3>ITENS DO PEDIDO</h3><div class="formgrid"><label>PRODUTO / RECEITA<select id="pItem" onchange="atualizaPrecoPedido()">${window.pedidoProdutos.map(p=>`<option value="${p.kind}_${p.ref}" data-kind="${p.kind}" data-ref="${p.ref}" data-nome="${v55Esc(p.nome)}" data-preco="${p.preco}">${v55Esc(p.kind)} - ${v55Esc(p.nome)} - ${v55Money(p.preco)}</option>`).join('')}</select></label><label>QUANTIDADE<input id="pQtd" type="number" step="0.001" value="1"></label><label>VALOR UNITÁRIO<input id="pValor" type="number" step="0.01" value="0"></label></div><button class="green" onclick="addItemPedido();aplicarFormaPagamento('p')">ADICIONAR ITEM</button><div id="pedidoCart"></div><h3>PAGAMENTO</h3><div class="formgrid"><label>DESC. AUTO<input id="pDescAuto" type="number" readonly value="0"></label><label>JUROS AUTO<input id="pJurosAuto" type="number" readonly value="0"></label><label>DESC. MANUAL<input id="pDescManual" type="number" value="0" oninput="renderPedidoCart()"></label><label>JUROS MANUAL<input id="pJurosManual" type="number" value="0" oninput="renderPedidoCart()"></label></div><div class="kpi" id="pedidoTotal">R$ 0,00</div><button onclick="salvarPedidoCompleto()">SALVAR PEDIDO</button><button class="secondary" onclick="fecharModal()">FECHAR</button>`);
    atualizaPrecoPedido(); renderPedidoCart(); aplicarFormaPagamento('p');
  }catch(e){alert('ERRO AO ABRIR PEDIDO: '+e.message)}
}
function preencherClientePedidoV55(){const id=$('pCliente')?.value; if(!id)return; api('/api/clientes').then(cs=>{const c=(cs||[]).find(x=>x.id===id); if(c){$('pClienteNome').value=c.nome||''; $('pTelefone').value=c.telefone||c.whatsapp||''; $('pEndereco').value=[c.rua,c.numero,c.bairro,c.cidade,c.estado].filter(Boolean).join(', ');}})}
function atualizaPrecoPedido(){const o=$('pItem')?.selectedOptions?.[0]; if(o&&$('pValor')) $('pValor').value=Number(o.dataset.preco||0).toFixed(2)}
function addItemPedido(){const o=$('pItem')?.selectedOptions?.[0]; if(!o)return alert('SELECIONE O ITEM.'); const q=v55Num($('pQtd').value), v=v55Num($('pValor').value); if(q<=0)return alert('INFORME A QUANTIDADE.'); window.pedidoCart=window.pedidoCart||[]; window.pedidoCart.push({produto_id:o.dataset.kind==='PRODUTO'?o.dataset.ref:null,receita_id:o.dataset.kind==='RECEITA'?o.dataset.ref:null,descricao:o.dataset.nome,quantidade:q,valor_unitario:v,total:q*v}); renderPedidoCart();}
function renderPedidoCart(){const subtotal=(window.pedidoCart||[]).reduce((s,i)=>s+v55Num(i.total),0), t=totalComPagamentos('p',subtotal); if($('pedidoCart')) $('pedidoCart').innerHTML=`${wrapTable(`<table><thead><tr><th>Descrição</th><th>Quantidade</th><th>Unitário</th><th>Total</th><th>Ação</th></tr></thead><tbody>${(window.pedidoCart||[]).map((i,idx)=>`<tr><td>${v55Esc(i.descricao)}</td><td>${v55Esc(i.quantidade)}</td><td>${v55Money(i.valor_unitario)}</td><td>${v55Money(i.total)}</td><td><button class="red" onclick="pedidoCart.splice(${idx},1);renderPedidoCart()">REMOVER</button></td></tr>`).join('')}</tbody></table>`) }<p>SUBTOTAL: <b>${v55Money(subtotal)}</b> | DESCONTO: <b>${v55Money(t.desconto)}</b> | JUROS: <b>${v55Money(t.juros)}</b></p>`; if($('pedidoTotal')) $('pedidoTotal').textContent=v55Money(t.total)}
async function salvarPedidoCompleto(){try{if(!(window.pedidoCart||[]).length)return alert('ADICIONE AO MENOS 1 ITEM.'); const subtotal=window.pedidoCart.reduce((s,i)=>s+v55Num(i.total),0), t=totalComPagamentos('p',subtotal); const body={id:window.pedidoEditId||undefined,cliente_id:$('pCliente').value||null,cliente_nome:$('pClienteNome').value||'CONSUMIDOR',telefone:$('pTelefone').value,data_entrega:$('pData').value||null,hora_entrega:$('pHora').value,entrega_tipo:$('pEntregaTipo').value,endereco_entrega:$('pEndereco').value,status:$('pStatus').value||'AGENDADO',subtotal,desconto:t.desconto,juros:t.juros,total:t.total,forma_pagamento:$('pForma').value,multa_percentual:v55Num($('pMultaPerc').value),prazo_cancelamento_horas:v55Num($('pPrazoCancel').value),observacoes:$('pObs').value,itens:window.pedidoCart}; await api('/api/pedidos/salvar-completo',{method:'POST',body:JSON.stringify(body)}); alert('PEDIDO SALVO.'); fecharModal(); pedidos();}catch(e){alert('ERRO AO SALVAR PEDIDO: '+e.message)}}
async function baixarPedidoVenda(id){const formas=await getFormasAvancadas(); abrirModal(`<h2>FINALIZAR PEDIDO</h2><p>Ao finalizar, o pedido vira venda, baixa estoque e fica somente para consulta.</p><label>FORMA DE PAGAMENTO<select id="bxForma">${formas.map(f=>`<option>${v55Esc(formaNome(f))}</option>`).join('')}</select></label><label>STATUS VENDA<select id="bxStatus"><option>PAGO</option><option>ABERTO</option></select></label><label><input id="bxEstoque" type="checkbox" checked> BAIXAR ESTOQUE</label><button class="green" onclick="confirmarBaixaPedido('${id}')">CONFIRMAR FINALIZAÇÃO</button><button class="secondary" onclick="fecharModal()">FECHAR</button>`)}
async function confirmarBaixaPedido(id){try{await api('/api/pedidos/baixar-venda/'+id,{method:'POST',body:JSON.stringify({forma_pagamento:$('bxForma').value,status:$('bxStatus').value,baixar_estoque:$('bxEstoque').checked})}); alert('PEDIDO FINALIZADO.'); fecharModal(); pedidos();}catch(e){alert('ERRO AO FINALIZAR: '+e.message)}}
